INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Dior Addict Peachy Glow', 'DIOR', 'Eau de Parfum - Jasmine and Peach Notes description ingredients application tips olfactory notes description Peachy Glow invigorates the peach facet of jasmine absolute, melting it into a cloud of vanilla whipped cream. A delicious floral saturation that captures the flower''s spirit in a sparkling syrup. Joyful and velvety, the Peachy Glow trail creates an enveloping olfactive harmony, a comforting delight with vibrant colors. Dior Addict elevates the fruity facet of Dior flowers in a collection of indulgent and colorful fragrances. Three scents, three ways to glow with delight. Let yourself be captivated by Purple Glow, dazzled by Rosy Glow, and embraced by Peachy Glow. ingredients #22072 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � VANILLIN � BUTYL METHOXYDIBENZOYLMETHANE � JASMINE OIL/EXTRACT � BENZYL BENZOATE � ROSE KETONES � LINALOOL � BENZYL ALCOHOL � COUMARIN � EUGENOL � AMYL SALICYLATE � CI 17200 (RED 33) application tips Spray Dior Addict Peachy Glow on pulse points - neck and wrists. Pair with Dior Addict Lip Glow Oil 041 Peachy, the lip oil with a "juicy" finish. olfactory notes Base Notes Vanilla whipped cream accord Heart Notes Jasmine absolute Top Notes Juicy peach accord MEMBER OF THE UNION FOR ETHICAL BIOTRADE, THE HOUSE OF DIOR IS COMMITTED TO SOURCING THAT IS RESPECTFUL OF NATURE AND LOCAL COMMUNITIES. description ingredients application tips olfactory notes description Peachy Glow invigorates the peach facet of jasmine absolute, melting it into a cloud of vanilla whipped cream. A delicious floral saturation that captures the flower''s spirit in a sparkling syrup. Joyful and velvety, the Peachy Glow trail creates an enveloping o