INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Dior Addict Purple Glow', 'DIOR', 'Eau de Parfum - Iris and Raspberry Notes description ingredients application tips olfactory notes description Purple Glow showcases the beauty of Tuscan iris with crystallized petals and candied raspberry nuances, like a crisp floral confection dusted with powdered sugar. Magnetic and intense, Purple Glow unfurls a captivatingly charming trail. Dior Addict elevates the fruity facet of Dior flowers in a collection of indulgent and colorful fragrances. Three scents, three ways to glow with delight. Let yourself be captivated by Purple Glow, dazzled by Rosy Glow, and embraced by Peachy Glow. ingredients #22071 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � VANILLIN � BUTYL METHOXYDIBENZOYLMETHANE � ROSE KETONES � BENZALDEHYDE � CI 17200 (RED 33) � CI 60730 (EXT. VIOLET 2) application tips Spray Dior Addict Purple Glow on pulse points - neck and wrists. Pair with Dior Addict Lip Glow Oil 104 Black Cherry, the lip oil with a "glaze" finish. olfactory notes Base Notes Vanilla whipped cream accord Heart Notes Tuscan iris butter Top Notes Candied raspberry accord MEMBER OF THE UNION FOR ETHICAL BIOTRADE, THE HOUSE OF DIOR IS COMMITTED TO SOURCING THAT IS RESPECTFUL OF NATURE AND LOCAL COMMUNITIES. description ingredients application tips olfactory notes description Purple Glow showcases the beauty of Tuscan iris with crystallized petals and candied raspberry nuances, like a crisp floral confection dusted with powdered sugar. Magnetic and intense, Purple Glow unfurls a captivatingly charming trail. Dior Addict elevates the fruity facet of Dior flowers in a collection of indulgent and colorful fragrances. Three scents, three ways to glow with delight. Let you