INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Dior Addict Rosy Glow', 'DIOR', 'Eau de Parfum - Rose and Lychee Notes description ingredients application tips olfactory notes description Under its soft pink shade, Rosy Glow unveils a glaze infused with Damascus rose essence with bright lychee accents, wrapped in a creamy accord evoking the caramelized notes of dulce de leche. Sparkling and good enough to eat, the Rosy Glow trail is a true olfactory confection that inspires a feeling of instant wonder. Dior Addict elevates the fruity facet of Dior flowers in a collection of indulgent and colorful fragrances. Three scents, three ways to glow with delight. Let yourself be captivated by Purple Glow, dazzled by Rosy Glow, and embraced by Peachy Glow. ingredients #22070 ALCOHOL � AQUA (WATER) � PARFUM (FRAGRANCE) � BUTYL METHOXYDIBENZOYLMETHANE � COUMARIN � ROSE FLOWER OIL/EXTRACT � VANILLIN � CITRONELLOL � GERANIOL � CITRAL � EUGENOL � PINENE � CI 60730 (EXT. VIOLET 2) application tips Spray Dior Addict Rosy Glow on pulse points - neck and wrists. Pair with Dior Addict Lip Glow Oil 077 Rose Candy, the lip oil with a "sparkly" finish. olfactory notes Base Notes Vanilla whipped cream accord Heart Notes Damascus rose essence Top Notes Sparkling lychee accord MEMBER OF THE UNION FOR ETHICAL BIOTRADE, THE HOUSE OF DIOR IS COMMITTED TO SOURCING THAT IS RESPECTFUL OF NATURE AND LOCAL COMMUNITIES. description ingredients application tips olfactory notes description Under its soft pink shade, Rosy Glow unveils a glaze infused with Damascus rose essence with bright lychee accents, wrapped in a creamy accord evoking the caramelized notes of dulce de leche. Sparkling and good enough to eat, the Rosy Glow trail is a true olfactory confection that