INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Dior Homme', 'DIOR', 'description ingredients application tips olfactory notes description Dior Homme Eau de Toilette is intriguingly powerful and appealingly fresh. Dior Homme redefines a new, masculine sensuality in a polyphony of smooth and raw wood. A heart of tender wood, in which the virility of Atlas Cedar embraces the enveloping warmth of Haitian Vetiver tinged with spice. Wood hand-chiseled by Dior. Dior Homme conveys all the facets of modern masculinity. A man, yes, but a man of many nuances: confident in both his strength and his tenderness. Dior Homme Eau de Toilette is a fragrance with a bold trail that leaves a sensual imprint. ingredients #13837/A ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � LIMONENE � ETHYLHEXYL METHOXYCINNAMATE � HYDROXYCITRONELLAL � LINALOOL � HEXYL CINNAMAL � CITRONELLOL � DIETHYLAMINO HYDROXYBENZOYL HEXYL BENZOATE � BHT � BUTYL METHOXYDIBENZOYLMETHANE � ETHYLHEXYL SALICYLATE � COUMARIN � CITRAL � GERANIOL � CI 47005 (YELLOW 10) � TOCOPHEROL � CI 14700 (RED 4) � CI 60730 (EXT. VIOLET 2) � CI 19140 (YELLOW 5) � application tips Prolong the trail of Dior Homme Eau de Toilette with the Dior Homme ritual: 1. Awaken the senses with the invigorating notes of the Dior Homme shower gel. 2. Soften your skin with the Dior Homme aftershave balm. 3. Freshen up with the Dior Homme spray deodorant. olfactory notes Base Notes Vetiver The molecule Iso E gradually settles into the composition, endlessly lingering and drawing out the sensuality of the scent of light wood. The only compound of its kind, it gives Dior Homme that inexplicable "deliciously clean" and fresh sensation. A persistent impression of washed wood, wholly contained in a single, rather magical, note. Heart Notes PATCHOULI HEART Like a friend who ties it all together, the Patchouli Heart is full and enveloping. It mingles with the virile woods to convey a caressing sensuality. Top Notes ATLAS CEDAR Atlas Cedar blows its dry and subtly leathery warmth through the trail of Dior Homme. Combined with Vetiver, it leads a polyphony of woods filled with tension and dialogue. MEMBER OF THE UNION FOR ETHICAL BIOTRADE, THE HOUSE OF DIOR IS COMMITTED TO SOURCING THAT IS RESPECTFUL OF NATURE AND LOCAL COMMUNITIES. description ingredients application tips olfactory notes description Dior Homme Eau de Toilette is intriguingly powerful and appealingly fresh. Dior Homme redefines a new, masculine sensuality in a polyphony of smooth and raw wood. A heart of tender wood, in which the virility of Atlas Cedar embraces the enveloping warmth of Haitian Vetiver tinged with spice. Wood hand-chiseled by Dior. Dior Homme conveys all the facets of modern masculinity. A man, yes, but a man of many nuances: confident in both his strength and his tenderness. Dior Homme Eau de Toilette is a fragrance with a bold trail that leaves a sensual imprint. ingredients #13837/A ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � LIMONENE � ETHYLHEXYL METHOXYCINNAMATE � HYDROXYCITRONELLAL � LINALOOL � HEXYL CINNAMAL � CITRONELLOL � DIETHYLAMINO HYDROXYBENZOYL HEXYL BENZOATE � BHT � BUTYL METHOXYDIBENZOYLMETHANE � ETHYLHEXYL SALICYLATE � COUMARIN � CITRAL � GERANIOL � CI 47005 (YELLOW 10) � TOCOPHEROL � CI 14700 (RED 4) � CI 60730 (EXT. VIOLET 2) � CI 19140 (YELLOW 5) � application tips Prolong the trail of Dior Homme Eau de Toilette with the Dior Homme ritual: 1. Awaken the senses with the invigorating notes of the Dior Homme shower gel. 2. Soften your skin with the Dior Homme aftershave balm. 3. Freshen up with the Dior Homme spray deodorant. olfactory notes Base Notes Vetiver The molecule Iso E gradually settles into the composition, endlessly lingering and drawing out the sensuality of the scent of light wood. The only compound of its kind, it gives Dior Homme that inexplicable "deliciously clean" and fresh sensation. A persistent impression of washed wood, wholly contained in a single, rather magical, note. Heart Notes PATCHOULI HEART Like a friend who ties it all together, the Patchouli Heart is full and enveloping. It mingles with the virile woods to convey a caressing sensuality. Top Notes ATLAS CEDAR Atlas Cedar blows its dry and subtly leathery warmth through the trail of Dior Homme. Combined with Vetiver, it leads a polyphony of woods filled with tension and dialogue. MEMBER OF THE UNION FOR ETHICAL BIOTRADE, THE HOUSE OF DIOR IS COMMITTED TO SOURCING THAT IS RESPECTFUL OF NATURE AND LOCAL COMMUNITIES. description Dior Homme Eau de Toilette is intriguingly powerful and appealingly fresh. Dior Homme redefines a new, masculine sensuality in a polyphony of smooth and raw wood. A heart of tender wood, in which the virility of Atlas Cedar embraces the enveloping warmth of Haitian Vetiver tinged with spice. Wood hand-chiseled by Dior. Dior Homme conveys all the facets of modern masculinity. A man, yes, but a man of many nuances: confident in both his strength and his tenderness. Dior Homme Eau de Toilette is a fragrance with a bold trail that leaves a sensual imprint. ingredients #13837/A ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � LIMONENE � ETHYLHEXYL METHOXYCINNAMATE � HYDROXYCITRONELLAL � LINALOOL � HEXYL CINNAMAL � CITRONELLOL � DIETHYLAMINO HYDROXYBENZOYL HEXYL BENZOATE � BHT � BUTYL METHOXYDIBENZOYLMETHANE � ETHYLHEXYL SALICYLATE � COUMARIN � CITRAL � GERANIOL � CI 47005 (YELLOW 10) � TOCOPHEROL � CI 14700 (RED 4) � CI 60730 (EXT. VIOLET 2) � CI 19140 (YELLOW 5) � application tips Prolong the trail of Dior Homme Eau de Toilette with the Dior Homme ritual: 1. Awaken the senses with the invigorating notes of the Dior Homme shower gel. 2. Soften your skin with the Dior Homme aftershave balm. 3. Freshen up with the Dior Homme spray deodorant. olfactory n