INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Dior Homme Parfum', 'DIOR', 'Fragrance - Ambery, Woody and Floral Notes description ingredients application tips olfactory notes description Discover Dior Homme Parfum reinvented by Francis Kurkdjian, Perfume Creative Director. A men''s fragrance crafted around a dual iris note, both airy and intense. The olfactory interpretation of modern masculinity, a balance between strength and tenderness. Dior Homme Parfum is the story of an encounter: the smooth, carnal notes of iris meet powerful ambery wood accords. A trail that expresses a masculine twist on the flower, with an overdose of iris creating an addictive, sensual, and elegant composition. The structure of the fragrance, airy yet dense, takes shape in a monolithic bottle with clean lines and a sensual color gradient. ingredients #21722 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � CITRUS AURANTIUM BERGAMIA (BERGAMOT) PEEL OIL � TETRAMETHYL ACETYLOCTAHYDRONAPHTHALENES � LIMONENE � LINALYL ACETATE � LINALOOL � COUMARIN � ALPHA-ISOMETHYL IONONE � PINENE � BUTYL METHOXYDIBENZOYLMETHANE � CITRUS AURANTIUM PEEL OIL � LAVANDULA OIL/EXTRACT � POGOSTEMON CABLIN OIL � GERANYL ACETATE � DIETHYLAMINO HYDROXYBENZOYL HEXYL BENZOATE � CAMPHOR � CITRAL � BETA-CARYOPHYLLENE � TERPINEOL � TERPINOLENE � GERANIOL � ALPHA-TERPINENE � ROSE KETONES � CINNAMOMUM ZEYLANICUM BARK OIL � CINNAMAL � FARNESOL � EUGENOL � ISOEUGENOL � CI 47005 (YELLOW 10) � CI 14700 (RED 4) � CI 60730 (EXT. VIOLET 2) application tips 1. Awaken the senses with the invigorating notes of Dior Homme shower gel. 2. Soften your skin with Dior Homme after-shave balm. 3. Refresh with Dior Homme deodorant. 4. Spray on Dior Homme Parfum for the finishing touch. olfactory notes Heart Notes AMBERY ACCORD A gourmet ambery accord where the density of patchouli meets a powerful vetiver, mingled with a note of coumarin and dry accents of cut hay. description ingredients application tips olfactory notes description Discover Dior Homme Parfum reinvented by Francis Kurkdjian, Perfume Creative Director. A men''s fragrance crafted around a dual iris note, both airy and intense. The olfactory interpretation of modern masculinity, a balance between strength and tenderness. Dior Homme Parfum is the story of an encounter: the smooth, carnal notes of iris meet powerful ambery wood accords. A trail that expresses a masculine twist on the flower, with an overdose of iris creating an addictive, sensual, and elegant composition. The structure of the fragrance, airy yet dense, takes shape in a monolithic bottle with clean lines and a sensual color gradient. ingredients #21722 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � CITRUS AURANTIUM BERGAMIA (BERGAMOT) PEEL OIL � TETRAMETHYL ACETYLOCTAHYDRONAPHTHALENES � LIMONENE � LINALYL ACETATE � LINALOOL � COUMARIN � ALPHA-ISOMETHYL IONONE � PINENE � BUTYL METHOXYDIBENZOYLMETHANE � CITRUS AURANTIUM PEEL OIL � LAVANDULA OIL/EXTRACT � POGOSTEMON CABLIN OIL � GERANYL ACETATE � DIETHYLAMINO HYDROXYBENZOYL HEXYL BENZOATE � CAMPHOR � CITRAL � BETA-CARYOPHYLLENE � TERPINEOL � TERPINOLENE � GERANIOL � ALPHA-TERPINENE � ROSE KETONES � CINNAMOMUM ZEYLANICUM BARK OIL � CINNAMAL � FARNESOL � EUGENOL � ISOEUGENOL � CI 47005 (YELLOW 10) � CI 14700 (RED 4) � CI 60730 (EXT. VIOLET 2) application tips 1. Awaken the senses with the invigorating notes of Dior Homme shower gel. 2. Soften your skin with Dior Homme after-shave balm. 3. Refresh with Dior Homme deodorant. 4. Spray on Dior Homme Parfum for the finishing touch. olfactory notes Heart Notes AMBERY ACCORD A gourmet ambery accord where the density of patchouli meets a powerful vetiver, mingled with a note of coumarin and dry accents of cut hay. description Discover Dior Homme Parfum rein