INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Extrait de Parfum COCO', 'Saff & Co', 'COCO carries the weight of untold legacy as the sun threaded its golden strands through noble gatherings amidst citrus orchards. A fragrant heirloom, weaving through generations like timeless tapestries of histories. Balsamic Bergamot Citrus Patchouli Woody', NULL, 18830000.0, 'Unisex', 'Seharian', 'Office / Formal', NULL, NULL, 'https://saffnco.com/products/extrait-de-parfum-coco', 0.0, 0.0, 'Extrait de Parfum', 'Bergamot', 'Cedar, Rose, Geranium', 'Patchouli', 'Woody, Citrus', 'Musim Gugur', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
