INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Extrait de Parfum KIE RAHA', 'Saff & Co', 'KIE RAHA sends an ode to the land that raised you. Here, cajuput holds the comfort of a safe embrace. Aquamare flows with clean, watery light, softened by a mineral touch that stirs quiet memories, while Sulawesi patchouli roots the warmth of generations in the first home that shaped you. Amber Bergamot Citrus Floral Mimosa New Arrival Oriental', NULL, 24900000.0, 'Unisex', 'Seharian', 'Casual / Daily', NULL, NULL, 'https://saffnco.com/products/extrait-de-parfum-kie-raha', 0.0, 0.0, 'Extrait de Parfum', 'Bergamot', 'Mimosa', 'Patchouli, Amber', 'Woody, Floral, Citrus, Oriental', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Dekat (Skin Scent)');
