INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Extrait de Parfum XOCOLATL', 'Saff & Co', 'A special SAFF & Co. collaboration with the most iconic cartoon series and the most beloved webcomic character-now available in Chocobi-inspired scent. XOCOLATL pays tribute to the first hot chocolate drink in the world-a luscious infusion that has earned a special place in the hearts of humankind for millennia. Gifted by God Quetzalcoatl as the Drink of the Deities, XOCOLATL was believed to be blended with sweet mandarin, creamy heliotrope and a secret aphrodisiac known only to the old gods & the lost civilization Bergamot Fresh Fruity Gourmand Sweet Tropical', NULL, 8900000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://saffnco.com/products/extrait-de-parfum-travel-size-xocolatl', 0.0, 0.0, 'Extrait de Parfum', 'Bergamot, Mandarin', 'Heliotrope', 'White Musk, Vetiver', 'Citrus, Fresh, Gourmand, Fruity', 'Musim Panas', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
