INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Gris Dior', 'DIOR', 'Unisex Eau de Parfum - Chypre Notes description ingredients application tips description GRIS DIOR, THE CHYPRE-ROSY SILHOUETTE PLEATED WITH CONTRASTS. Gris Dior eau de parfum is an olfactory enigma that forms an indivisible whole, a reflection of its namesake color. Like chypre-rosy pleats, Gris Dior unfolds its different floral and woody facets in turn. A sensation of fullness and volume is thus created, a unisex silhouette with multiple olfactory hues that come together in a mysterious chypre trail punctuated with notes of citrus, rose, violet and then oak moss. A unisex eau de parfum that plays with contrasts, Gris Dior reveals the boldest nuances for those who wear it. Regal fragrance, scent of elegance, which the color gray represents at Dior, it encapsulates the spirit of the House and stands today as the icon of La Collection Priv�e Christian Dior. ingredients WARNING: THE LISTS OF INGREDIENTS THAT MAKE UP THE COMPOSITION OF PARFUMS CHRISTIAN DIOR PRODUCTS ARE REGULARLY UPDATED. BEFORE USING A PARFUMS CHRISTIAN DIOR PRODUCT, PLEASE READ THE LIST OF INGREDIENTS LOCATED ON THE PACKAGING TO BE CERTAIN THAT THE INGREDIENTS ARE SUITABLE FOR YOUR PERSONAL USE. #20555 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � ALPHA-ISOMETHYL IONONE � BENZYL SALICYLATE � LINALOOL � LIMONENE � BUTYL METHOXYDIBENZOYLMETHANE � CITRONELLOL � DIETHYLAMINO HYDROXYBENZOYL HEXYL BENZOATE � GERANIOL � EVERNIA PRUNASTRI (OAKMOSS) EXTRACT � CITRAL � BENZYL ALCOHOL � EUGENOL � BENZYL BENZOATE � CI 60730 (EXT. VIOLET 2) � CI 14700 (RED 4) � CI 47005 (YELLOW 10) application tips Spray Gris Dior on pulse points: neck and wrists. description ingredients application tips description GRIS DIOR