INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Addict Eau De Parfum 100 ml', 'HMNS', 'Bayangkan sebuah malam yang sunyi, di saat dunia terasa melambat. Di sana, ada kehangatan yang lembut menyelimuti, aroma yang membangkitkan kenangan, dan menggoda. Di awal, beri merah yang segar menyapa dengan manis yang memikat, seolah membangunkan gairah dalam satu hirupan. Lalu perlahan, mawar merah yang elegan mulai menyeruak, menambahkan sentuhan romantis yang dalam. Kemudian, saat wangi mulai menetap, hadir aroma patchouli, amber yang hangat, dan tonka yang sedikit manis, menciptakan aroma yang hangat.', NULL, 36900000.0, 'Pria', 'Malam', 'Date / Romantic', NULL, NULL, 'https://madeforhmns.com/products/addict-100ml', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Bergamot, Ginger', 'Mawar', 'Tonka, Patchouli, Amber', 'Woody, Floral, Oriental, Fresh', 'Musim Gugur', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Alpha Eau De Parfum 100 ml', 'HMNS', 'Alpha adalah salah satu parfum maskulin pertama HMNS. Nama �Alpha� terinspirasi dari huruf pertama alfabet, �A�, melambangkan awal dari sesuatu yang baru. Bayangin kamu lagi jalan pagi-pagi di hutan, segarnya udara yang penuh aroma kayu dan dedaunan basah, lalu kamu duduk di depan teras rumah kamu sambil menikmati teh hangat. notes__Wood', NULL, 32000000.0, 'Pria', 'Pagi / Siang', 'Office / Formal', NULL, NULL, 'https://madeforhmns.com/products/alpha-100ml', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Bergamot, Ginger', 'Cedar, Rose, Geranium', 'Sandalwood, Vetiver, Patchouli, Musk', 'Woody, Fresh', 'Musim Panas', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Alpha Hyper Green Extrait 100 ml', 'HMNS', 'You know Alpha. HMNS'' very first perfume. Born from the essence of green tea. Hyper Green is Alpha that didn�t stop there. It grew, as you grew. It became stronger. Longer. Greener. Sebagai Extrait de Parfum, Hyper Green dibuka dengan nuansa hijau yang bersih dari Pure Natural Lemon Oil, Pink Pepper dan Cactus Accord. Dipertajam oleh Ciste Absolute, dan akhirnya menetap sebagai aroma hijau yang mengakar dari Patchouli Indonesia, Vetiver Java dan Moss', NULL, 52500000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://madeforhmns.com/products/hmns-hyper-green-extrait-de-parfum', 0.0, 0.0, 'Extrait de Parfum', 'Pink Pepper, Lemon', 'Cedar, Rose, Geranium', 'Patchouli, Vetiver', 'Woody, Citrus, Spicy, Green', 'Musim Panas', 'Sangat Tahan Lama (8+ jam)', 'Sangat Kuat (Loud)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Ambar Janma Eau De Parfum 100 ml', 'HMNS', 'Sebuah terobosan baru dalam dunia wewangian�Ambar Janma, parfum pertama dari HMNS yang menggunakan teknologi paten The Impossible Scent�?. Diciptakan dengan dua lapisan aroma, Ambar dan Janma bekerja secara sinergis untuk menciptakan pengalaman wangi yang unik dan tak tertandingi. Ambar adalah fondasi yang menetap di kulit, memberikan kehangatan yang mendalam dan elegan. Sementara Janma memberikan kekuatan dan proyeksi, menjadikan aromanya semakin hidup.', NULL, 51000000.0, 'Pria', 'Pagi / Siang', 'Office / Formal', NULL, NULL, 'https://madeforhmns.com/products/hmns-perfume-ambar-janma-manusia-harum', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Apple, Peach', 'Raspberry, Blackcurrant, Peach', 'Musk, Vanilla, White Wood', 'Fruity, Leather', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Another Rose Nourishing Hair Perfume 250 ml', 'HMNS', 'Terinspirasi dari wangi best-seller Unrosed, kini keanggunan aroma itu hadir dalam bentuk yang lebih personal untuk rambutmu. Perpaduan floral fruity yang menyentuh lembut, seperti saat kelopak Rose yang mekar bertemu dengan keharuman segar dan bersih dari Lily of the Valley, dibalut sentuhan buah yang manis dan menyegarkan. Wanginya ringan, tapi meninggalkan kesan mendalam di setiap helai rambutmu. Tak hanya meninggalkan jejak aroma yang memikat, formulanya juga dirancang untuk merawat rambut secara menyeluruh dengan 3 Active Ingredients. Ethyl Macadamiate membantu melindungi rambut dari panas alat styling & paparan sinar matahari. Amino Acid Complex memperkuat struktur rambut. Lalu Trehalose menjaga kelembaban alami rambut agar tetap terasa ringan, dan tampak berkilau sepanjang hari.', NULL, 19500000.0, 'Pria', 'Seharian', 'Sport / Outdoor', NULL, NULL, 'https://madeforhmns.com/products/hmns-nourishing-hair-perfume-another-rose', 0.0, 0.0, NULL, 'Rose, Jasmine', 'Rose, Lily', 'Musk, Sandalwood, White Cedar', 'Floral, Fresh, Gourmand, Fruity', 'Musim Panas', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
