INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Atomizer Black Doff 8ml', 'HMNS', 'Parfum favorit kamu, sekarang bisa lebih praktis dibawa ke mana saja. HMNS Atomizer hadir sebagai solusi untuk kamu yang selalu aktif dan ingin tetap wangi sepanjang hari. Tidak perlu lagi membawa botol parfum besar�cukup isi Atomizer dengan parfum HMNS favoritmu, dan kamu siap beraktivitas tanpa masalah.', NULL, 6900000.0, 'Pria', 'Seharian', 'Date / Romantic', NULL, NULL, 'https://madeforhmns.com/products/hmns-perfume-atomizer', 0.0, 0.0, 'Parfum', 'Bergamot, Cardamom', 'Rose, Jasmine, Ylang-Ylang', 'Amber, Musk, Sandalwood, Patchouli', 'Oriental', 'Musim Gugur', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Darker Shade of O Nourishing Hair Perfume 250 ml', 'HMNS', 'Terinspirasi oleh wangi best-seller Darker Shade of Orgsm, Nourishing Hair Perfume varian ini menghadirkan kesegaran Apple yang menggoda, berpadu dengan kelembutan Caramel yang manis dan hangat. Seiring berjalannya waktu, sentuhan Cedarwood yang dalam memberi kesan misterius dan bold. Setiap gerakan helaian rambutmu kini menjadi terasa lebih sensual dan seakan membawa aura yang sulit dilupakan. Tak hanya tentang aroma, formula ini juga menjaga rambut tetap sehat dengan Ethyl macadamiate yang bekerja melindungi rambut dari panas alat styling & sinar matahari. Lalu ada Amino Acid Complex yang memperkuat rambut. Juga Trehalose yang membantu mempertahankan kelembaban alami, membuat rambut terasa halus dan terlindungi sepanjang hari.', NULL, 19500000.0, 'Pria', 'Malam', 'Office / Formal', NULL, NULL, 'https://madeforhmns.com/products/hmns-nourishing-hair-perfume-darker-shade-of-o', 0.0, 0.0, NULL, 'Bergamot, Ginger', 'Cedar, Rose, Geranium', 'Cedar, Cedarwood', 'Woody, Fresh, Gourmand, Fruity', 'Musim Panas', 'Sangat Tahan Lama (8+ jam)', 'Sangat Kuat (Loud)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Darker Shade of ORGSM Eau De Parfum 100 ml', 'HMNS', 'What if we create an alter ego of HMNS ORGSM? Bayangin, sebuah versi di mana kamu bisa melihat sisi lain dari diri kamu� the darker shade of you. Versi yang penuh misteri, diciptakan untuk mereka yang berani mengeksplorasi sisi tersembunyi dari kepribadian mereka.', NULL, 38000000.0, 'Pria', 'Pagi / Siang', 'Casual / Daily', NULL, NULL, 'https://madeforhmns.com/products/hmns-perfume-darker-shades-of-orgasm-eau-de-parfum', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Apple, Peach', 'Raspberry, Blackcurrant, Peach', 'Musk, Vanilla, White Wood', 'Fruity', 'Musim Dingin', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Drops of Sunshine Hair & Body Mist 250 ml', 'HMNS', 'Inspired by the beauty of the Goddess of Dawn, Drops of Sunshine adalah hair & body mist yang dirancang untuk memberikan aroma oriental floral dengan sentuhan creamy gourmand yang lembut dan menenangkan baik untuk tubuh maupun rambut kamu.', NULL, 14500000.0, 'Pria', 'Seharian', 'Casual / Daily', NULL, NULL, 'https://madeforhmns.com/products/hmns-hair-body-mist-drop-of-sunshine', 0.0, 0.0, 'Body Mist', 'Rose, Jasmine', 'Peony, Lily of the Valley, Magnolia', 'Musk, Sandalwood, White Cedar', 'Floral, Oriental', 'Musim Semi', 'Cepat Hilang (<2 jam)', 'Dekat (Skin Scent)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Elea Fragrance Mist 250 ml', 'HMNS', 'Sebuah kolaborasi spesial antara HMNS x Tsana (Rintik Sedu), Elea adalah sosok yang menemani, melindungi, dan memberikan kehangatan dalam setiap langkahmu. Elea hadir sebagai dewi yang tak kasat mata. Dia muncul setiap kali kamu menyemprotkannya, menyelimuti tubuhmu dengan keharuman yang lembut namun penuh karakter. Ia akan terasa seperti pelukan di hari-hari sulit, seperti suara yang menenangkan di tengah riuh dunia. Dia tidak berbicara, tapi kamu bisa merasakannya.', NULL, 18500000.0, 'Pria', 'Pagi / Siang', 'Casual / Daily', NULL, NULL, 'https://madeforhmns.com/products/hmns-x-tsana-fragrance-mist-elea', 0.0, 0.0, NULL, 'Apple, Peach', 'Raspberry, Blackcurrant, Peach', 'Musk, Vanilla, White Wood', 'Fruity', 'Musim Semi', 'Sedang (2-4 jam)', 'Sedang (Moderate)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS EOS Hyper Nova Extrait 100 ml', 'HMNS', 'From Essence of The Sun. The same solar warmth, with more concentrated sun-kissed floral. Aroma Solar Accord yang dibuka dengan wangi Cocoa Butter yang creamy dan hangat, dengan wangi Jasmine, Ylang-ylang dan Vanila, yang mengingatkanmu pada EoS dalam versi yang lebih kaya, powdery, dan .', NULL, 52500000.0, 'Pria', 'Seharian', 'Casual / Daily', NULL, NULL, 'https://madeforhmns.com/products/hmns-hyper-nova-extrait-de-parfum', 0.0, 0.0, 'Extrait de Parfum', 'Rose, Jasmine', 'Jasmine, Ylang-Ylang', 'Musk, Sandalwood, White Cedar', 'Floral, Gourmand', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Essence of The Sun Eau De Parfum 100 ml', 'HMNS', '"Panggil aku Eos. Aku adalah esensi dari matahari. Dewi fajar. Dan cahaya pertama di pagi hari." Aroma matahari, begitu orang-orang menyebutnya. Eos adalah parfum akor solar pertama dari HMNS. Campuran eksotis yang diekstrak dari tiga bunga tropis yang dikeringkan sepanjang hari untuk menciptakan gelombang aroma yang cerah. Wear this proudly & go crazy as you create memories because you know that you will.. #BeRemembered', NULL, 36900000.0, 'Pria', 'Pagi / Siang', 'Office / Formal', NULL, NULL, 'https://madeforhmns.com/products/essence-of-the-sun-eos-100ml-edp', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Bergamot, Ginger', 'Cedar, Rose, Geranium', 'Oud', 'Woody, Floral, Oriental', 'Musim Panas', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Farhampton Parfum 100 ml', 'HMNS', 'Farhampton adalah teman sejati yang akan menemani setiap langkahmu hingga akhir perjalanan. Dengan konsentrasi wewangian murni yang tinggi, parfum ini seperti ungkapan dalam menemukan soulmate. Setiap semprotan Farhampton membawamu ke suasana bahagia dan menyenangkan.', NULL, 36900000.0, 'Pria', 'Malam', 'Date / Romantic', NULL, NULL, 'https://madeforhmns.com/products/farhampton-100ml-extrait-de-parfum', 0.0, 0.0, 'Parfum', 'Bergamot, Cardamom', 'Rose, Jasmine, Ylang-Ylang', 'Amber, Musk, Sandalwood, Patchouli', 'Oriental', 'Musim Gugur', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS My 1st O Hair & Body Mist 250 ml', 'HMNS', 'My 1st O adalah versi hair & body mist dari varian fragrance best-selling ORGSM . Didesain dengan twist segar dari raspberry dan trehalose, produk ini tidak hanya memberikan keharuman yang mewah tetapi juga menjaga rambut tetap terhidrasi dan terasa lembut sepanjang hari.', NULL, 13900000.0, 'Pria', 'Seharian', 'Sport / Outdoor', NULL, NULL, 'https://madeforhmns.com/products/hmns-hair-body-mist-my-1st-o', 0.0, 0.0, 'Body Mist', 'Marine, Ozone, Green Notes', 'Lavender, Aquatic Notes', 'White Musk, Cedar', 'Fresh, Fruity', 'Musim Panas', 'Cepat Hilang (<2 jam)', 'Dekat (Skin Scent)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS O Hyper Bloom Extrait 100 ml', 'HMNS', 'Imagine the very essence of Red Apple, Jasmine, and Amber. The world''s most bestselling notes for women, concentrated into the purest form of pleasure. Introducing a hyper blooming formula of O. Masih dengan Apple sebagai pembuka, namun dengan wangi floral yang lebih intens dari Tuberose dan Jasmine. Ditutup dengan wangi yang lebih manis, hangat, dan sensual dari Amber, yang akan tinggal jauh lebih lama di kulitmu.', NULL, 52500000.0, 'Pria', 'Malam', 'Date / Romantic', NULL, NULL, 'https://madeforhmns.com/products/hmns-hyper-bloom-extrait-de-parfum', 0.0, 0.0, 'Extrait de Parfum', 'Rose, Jasmine', 'Tuberose, Jasmine, Rose', 'Amber', 'Floral, Oriental, Gourmand, Fruity', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS ORGSM Eau De Parfum 100 ml', 'HMNS', 'Kenalin, ini ORGSM, parfum feminin pertama dari HMNS. Parfum ini dibuat dari ide menggabungkan tiga bunga di dunia, yaitu Rose, Peony, dan Jasmine dalam satu botol parfum. ORGSM juga sudah memenangkan banyak penghargaan, salah satunya dari Female Daily sebagai Best Indonesian Fragrance. Ia hadir buat merayakan kamu, untuk memanjakan diri kamu dengan setiap semburannya, membawamu ke alam semesta berisi kesenangan dan cinta.', NULL, 32300000.0, 'Pria', 'Seharian', 'Casual / Daily', NULL, NULL, 'https://madeforhmns.com/products/orgsm', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Rose, Jasmine', 'Jasmine, Rose, Peony', 'Musk, Sandalwood, White Cedar', 'Floral', 'Musim Semi', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS ORGSM Melting Temptation Eau De Parfum 100 ml', 'HMNS', 'Dulu, kita menciptakan ORGSM , parfum yang menggabungkan bunga-bunga dunia dalam satu botol . Perfume that celebrates human pleasure. ??But have you ever thought.. What if we take this sensation to the next level? Bukan cuma wangi floral yang mewah, tapi sesuatu yang lebih creamy, milky, dan sweet melebur dalam satu botol? Dari situ, lahirlah parfum yang beraroma manis karamel, segarnya apel dan pir yang juicy, mengalir ke aroma coklat pekat . Dan di akhir? Vanilla, amber, dan musk yang lembut dan hangat, meninggalkan jejak aroma yang sulit dilupakan. Wear it, and see for yourself. A magnetic force that keeps everyone coming back for more. In a creation that we call. secret__orgsm', NULL, 38000000.0, 'Pria', 'Malam', 'Date / Romantic', NULL, NULL, 'https://madeforhmns.com/products/orgsm-melting-temptation', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Rose, Jasmine', 'Peony, Lily of the Valley, Magnolia', 'Musk, Vanilla, Amber', 'Floral, Oriental, Fresh, Gourmand', 'Musim Semi', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Philea Eau De Parfum 100 ml', 'HMNS', 'HMNS Perfume - Philea 100ml Elea adalah seorang teman yang selalu ada untukmu. Tapi dunia berputar dan kamu menghadapi dewasa. Kita butuh teman lain yang menemanimu bertumbuh. Bersama Tsana, kita menemukan bunga Mimosa. Ia menjelma menjadi sosok peri yang merayakanmu bersemi dengan bungamu sendiri. Dengan wangi Magnolia, Mimosa dan Cashmeran yang kuat tapi lembut. Perkenalkan, ini Elea EDP, atau bisa kamu panggil� Philea. Ketahanan: 6�8 jam. Jejak Aroma: Meninggalkan aroma yang cukup kuat saat kamu lewat. Jangkauan: Tercium hingga 1,5�2 meter. Pengiriman Pengiriman setiap hari Senin sampai Jumat, dan batas pemesanan agar dikirim dihari yang sama jam 12 siang. Lebih dari jam 12 siang masuk pengiriman besok harinya. Tidak ada pengiriman di tanggal merah dan Weekend. Pemesanan hari Jumat akan di kirim di hari Senin sore. Untuk pengiriman via kurir instan untuk launching pertama kali belum disediakan. Pengiriman dilakukan dari Jakarta, dan durasi pengiriman disesuaikan dengan kebijakan jarak dan ketepatan waktu masing-masing jasa antar. Apabila ada kendala silahkan langsung menghubungi CS HMNS, dan kami akan langsung membantu. Love, HMNS.', NULL, 38500000.0, 'Pria', 'Pagi / Siang', 'Date / Romantic', NULL, NULL, 'https://madeforhmns.com/products/hmns-perfume-philea-100ml', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Rose, Jasmine', 'Mimosa, Magnolia', 'Musk, Sandalwood, White Cedar', 'Floral', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
