INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS SORE Zena Fragrance Mist 250 ml', 'HMNS', 'HMNS Sore �ena Fragrance Mist 250ml Sebuah karya kolaborasi bersama film Sore: Istri dari Masa Depan. Terinspirasi dari kata �ena, yang artinya �istri�. Seperti rasa cinta Sore yang hangat dan manis kepada Jonathan, sebagai seorang istri yang datang dari masa depan. Dibuka dengan wangi yang manis dan ceria dari Mandarin, Pinneaple dan Coconut Milk. Dan ditutup dengan wangi creamy dan woody, dari Vanilla, Sandalwood, dan Virgina Cedar. Longevity : 2 - 3 hours Sillage : medium Projection : 1-1.5 meter Pengiriman Pengiriman setiap hari Senin sampai Jumat, dan batas pemesanan agar dikirim dihari yang sama jam 12 siang. Lebih dari jam 12 siang masuk pengiriman besok harinya. Tidak ada pengiriman di tanggal merah dan Weekend. Pemesanan hari Jumat akan di kirim di hari Senin sore. Untuk pengiriman via kurir instan untuk launching pertama kali belum disediakan. Pengiriman dilakukan dari Jakarta, dan durasi pengiriman disesuaikan dengan kebijakan jarak dan ketepatan waktu masing-masing jasa antar. Apabila ada kendala silahkan langsung menghubungi CS HMNS, dan kami akan langsung membantu. Love, HMNS.', NULL, 18500000.0, 'Pria', 'Pagi / Siang', 'Date / Romantic', NULL, NULL, 'https://madeforhmns.com/products/hmns-x-sore-fragrance-mist-zena', 0.0, 0.0, NULL, 'Mandarin', 'Cedar, Rose, Geranium', 'Sandalwood, Cedar, Vanilla', 'Woody, Citrus, Oriental, Gourmand', 'Musim Gugur', 'Sedang (2-4 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS The Discovery Set 50 ml', 'HMNS', 'Dengan HMNS Discovery Set, kamu dapat menjelajahi 5 aroma terbaik dari HMNS. Set ini dirancang untuk membantu kamu menemukan parfum yang paling sesuai dengan kepribadian dan cerita kamu. Dengan 5 mini parfum, voucher belanja, dan pouch eksklusif, Discovery Set adalah pilihan ideal untuk mengeksplorasi atau memberikan hadiah kepada orang terdekat kamu.', NULL, 28900000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://madeforhmns.com/products/hmns-perfume-the-discovery-set', 0.0, 0.0, 'Parfum', 'Lavender, Rosemary', 'Lavender, Geranium, Sage', 'Oakmoss, Cedarwood, Musk', 'Aromatic', 'Musim Semi', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS The Perfection Eau De Parfum 100 ml', 'HMNS', '"Kesempurnaan tidak mudah dicapai, tetapi selalu layak diperjuangkan." Dirancang bersama Christian Sugiono, The Perfection adalah parfum HMNS dengan karakter spicy fougere yang menciptakan kesan mewah dan bersih. Di HMNS, kami percaya bahwa kesempurnaan adalah hasil dari dedikasi dan kerja keras. Dibutuhkan 145 percobaan untuk menyempurnakan mahakarya ini, agar kamu dapat merasakan versi terbaik dari diri kamu setiap hari.', NULL, 39800000.0, 'Pria', 'Pagi / Siang', 'Office / Formal', NULL, NULL, 'https://madeforhmns.com/products/hmns-perfume-the-perfection', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Marine, Ozone, Green Notes', 'Lavender, Aquatic Notes', 'White Musk, Cedar', 'Fresh, Spicy, Green', 'Musim Panas', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS The Prestige Eau De Parfum 100 ml', 'HMNS', 'Ini adalah produk kolaborasi antara HMNS dan Christian Sugiono. Ia hadir untuk merayakan setiap langkah kecil yang kamu ambil dan setiap keberhasilan yang kamu capai. Karena kita percaya setiap perjuangan panjang kamu, setiap hasil yang kamu dapat, semua itu pantas dirayakan. Dengan aroma yang rich dan sedikit smoky, ditambah sentuhan tobacco sebagai highlight, parfum ini diciptakan untuk kamu yang selalu berani meraih impian.', NULL, 39800000.0, 'Unisex', 'Seharian', 'Casual / Daily', NULL, NULL, 'https://madeforhmns.com/products/hmns-perfume-the-prestige', 0.0, 0.0, 'Eau de Parfum (EDP)', NULL, NULL, 'Tobacco', 'Leather', 'Semua Musim', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Unpatched Eau De Parfum 100 ml', 'HMNS', 'HMNS Unpatched adalah inovasi unggulan dari HMNS, sebuah perpaduan antara sains modern dan seni perfumery. Parfum ini menggunakan akigalawood , bahan bio-engineered yang menggantikan patchouli dengan karakter aroma woody dan green leathery yang unik. Menariknya, semakin lama dipakai, wanginya akan semakin memukau.', NULL, 39800000.0, 'Pria', 'Pagi / Siang', 'Party / Night', NULL, NULL, 'https://madeforhmns.com/products/hmns-perfume-unpatched', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Bergamot, Ginger', 'Cedar, Rose, Geranium', 'Patchouli, Leather', 'Woody, Fruity, Leather, Green', 'Musim Gugur', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Unrosed Eau De Parfum 100 ml', 'HMNS', 'Sebuah mahakarya yang diciptakan dengan teknik Soliflore�sebuah seni untuk membangun aroma bunga tunggal, tanpa menggunakan bunga itu sendiri. Unrosed mengangkat keindahan mawar dengan cara yang berbeda, dirancang dari ekstraksi Palmarosa, tanaman asli Indonesia, yang dipadukan dengan elemen lain untuk menciptakan nuansa bunga mawar yang unik. Wangi Unrosed menyebarkan sensualitas aksen floral yang lembut, seimbang dengan aroma woody dan earthy yang membumi, lalu diperkuat dengan sentuhan musky yang memberikan kesan mewah dan elegan. Ini bukan sekadar wangi bunga mawar�ini adalah interpretasi modern yang terasa lebih berkarakter.', NULL, 37400000.0, 'Pria', 'Malam', 'Date / Romantic', NULL, NULL, 'https://madeforhmns.com/products/unrosed', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Bergamot, Ginger', 'Mawar, Rose', 'Musk', 'Woody, Floral, Oriental, Fruity', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('HMNS Untitled Humans Aroma 01 Eau De Parfum 100 ml', 'HMNS', 'Dalam kolaborasi eksklusif antara HMNS dan Maliq & D''Essentials, kita mengajak kamu untuk merayakan keunikan kamu tanpa label. Kita paham kalau manusia adalah makhluk yang kompleks, dan wewangian ini merupakan bentuk dari kebebasan ekspresi diri kamu yang kami namakan.. Untitled Humans. Ini adalah varian pertama dari seri tersebut yang dinamakan Aroma 01, yang memiliki notes fig dan skamulwood. Notes ini melambangkan kesederhanaan dan kehangatan, menggambarkan kedalaman karakter yang unik dan abadi.', NULL, 39500000.0, 'Pria', 'Seharian', 'Office / Formal', NULL, NULL, 'https://madeforhmns.com/products/untitled-humans', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Bergamot, Ginger', 'Cedar, Rose, Geranium', 'Sandalwood, Vetiver, Patchouli, Musk', 'Woody', 'Musim Gugur', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
