INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Miss Dior Eau de Parfum Mini Miss Solid Perfume Refill', 'DIOR', 'Solid Perfume Refill - Velvety and Sensual Notes description ingredients application tips olfactory notes description The Miss Dior Eau de Parfum Mini Miss solid perfume is refillable: once finished, replace your fragrance stick with a new refill for continued use. For the 1st time, the House of Dior has developed an alcohol-free solid perfume formula with a clear finish and made from * natural-origin ingredients. Enriched with rose wax, this solid perfume leaves skin feeling soft and moisturized. The stick offers a moment of sensorial indulgence with each touch-up thanks to its non-sticky and comfortable texture. Miss Dior Eau de Parfum Mini Miss is characterized by a velvety and sensual signature, reigned over by a rose note highlighted by accents of fresh lily-of-the-valley, a peony accord and a powdery iris note. The solid perfume refill is sold separately. * Amount calculated based on the ISO 16128-1 and ISO 16128-2 standard. The remaining contribute to the formula�s performance, sensory appeal and stability. ingredients #18962 OCTYLDODECANOL � COCO-CAPRYLATE/CAPRATE � PARFUM (FRAGRANCE) � DIBUTYL LAUROYL GLUTAMIDE � PHYTOSTERYL/OCTYLDODECYL LAUROYL GLUTAMATE � DIBUTYL ETHYLHEXANOYL GLUTAMIDE � LINALOOL � LIMONENE � HYDROXYCITRONELLAL � GERANIOL � ROSA CENTIFOLIA FLOWER WAX � ROSA DAMASCENA FLOWER WAX � COUMARIN � CITRONELLOL � PENTAERYTHRITYL TETRA-DI-T-BUTYL HYDROXYHYDROCINNAMATE � TOCOPHEROL � POLYGLYCERYL-2 TRIISOSTEARATE � FARNESOL � CITRAL � TRIMETHYLOLPROPANE TRIISOSTEARATE � CI 45410 (RED 28 LAKE) � CI 15850 (RED 6) � BENZYL BENZOATE � PROPYL GALLATE application tips Unclip the empty, old refill by pulling the silvery case and replace it with a new solid fragrance refill. olfactory notes Base Notes Tender woods Softly comforting musks, a vanilla note and a hint of Tonka bean mingle with sandalwood accords. Heart Notes Rose The rose exudes a subtly spicy floral note. Top Notes Floral bouquet The floral freshness of lily-of-the-valley notes, an expressive peony accord and caressing iris notes accompany a slightly dewy verdant quality. MEMBER OF THE UNION FOR ETHICAL BIOTRADE, THE HOUSE OF DIOR IS COMMITTED TO SOURCING THAT IS RESPECTFUL OF NATURE AND LOCAL COMMUNITIES. description ingredients application tips olfactory notes description The Miss Dior Eau de Parfum Mini Miss solid perfume is refillable: once finished, replace your fragrance stick with a new refill for continued use. For the 1st time, the House of Dior has developed an alcohol-free solid perfume formula with a clear finish and made from * natural-origin ingredients. Enriched with rose wax, this solid perfume leaves skin feeling soft and moisturized. The stick offers a moment of sensorial indulgence with each touch-up thanks to its non-sticky and comfortable texture. Miss Dior Eau de Parfum Mini Miss is characterized by a velvety and sensual signature, reigned over by a rose note highlighted by accents of fresh lily-of-the-valley, a peony accord and a powdery iris note. The solid perfume refill is sold separately. * Amount calculated based on the ISO 16128-1 and ISO 16128-2 standard. The remaining contribute to the formula�s performance, sensory appeal and stability. ingredients #18962 OCTYLDODECANOL � COCO-CAPRYLATE/CAPRATE � PARFUM (FRAGRANCE) � DIBUTYL LAUROYL GLUTAMIDE � PHYTOSTERYL/OCTYLDODECYL LAUROYL GLUTAMATE � DIBUTYL ETHYLHEXANOYL GLUTAMIDE � LINALOOL � LIMONENE � HYDROXYCITRONELLAL � GERANIOL � ROSA CENTIFOLIA FLOWER WAX � ROSA DAMASCENA FLOWER WAX � COUMARIN � CITRONELLOL � PENTAERYTHRITYL TETRA-DI-T-BUTYL HYDROXYHYDROCINNAMATE � TOCOPHEROL � POLYGLYCERYL-2 TRIISOSTEARATE � FARNESOL � CITRAL 