INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Affair Extrait de Parfum 100ml', 'Mykonos', 'Mykonos - Affair Extrait de Parfum 100ml A fragrance crafted as an ode to the celebration of self-love and the flirty nature of a woman embracing her own essence. This enchanting perfume captures the spirit of a playful rendezvous with oneself. Affair opens with a burst of icy, sweet, and tangy raspberry sorbet', NULL, 200000.0, 'Pria', 'Seharian', 'Date / Romantic', NULL, NULL, NULL, 0.0, 0.0, 'Extrait de Parfum', 'Raspberry Sorbet, Pink Pepper Middle Notes: Rose, Peony Base Notes: Vanilla, Patchouli, Cashmere Wood, Salted Caramel No', 'Rose, Peony Base Notes: Vanilla, Patchouli, Cashmere Wood, Salted Caramel No', 'Vanilla, Patchouli, Cashmere Wood, Salted Caramel No', 'Woody, Floral, Oriental, Gourmand', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Aphrodite Extrait de Parfum 50ml & 100ml', 'Mykonos', 'Mykonos - Aphrodite Extrait de Parfum 50ml & 100ml The scent of self love and self obsession. Aphrodite adopts the concept of Greek Goddess �Aphrodite� and takes it to the modern world. The opening scent of myrrh, burnt cinnamon, and jasmine is reminiscent of a Jazz club where a young woman sits by the bar, you can smell her white floral and sandalwood perfume from a distance, bewitchingly beautiful. Her suede red dress perfectly represents her beautiful mystery, You can�t help but get curious to know who she is� As you get closer, you smell sensual musks mixed with smoky tobacco. It�s so addictive in a way you can�t explain and no matter how close you get, she won�t bat an eye. Enclosed in a bubble of mystery, she�s grooving to the music she loves, happy in her own thoughts. She knows however, she�s got your attention. Top Notes: Jasmine, Burnt Cinnamon, Myrrh Middle Notes: Cedarwood, Tonka Bean, Sandalwood Base Notes: White Musk, Tobacco, Vanilla, Mineral Amber No : NA18240607827', NULL, 29900000.0, 'Pria', 'Malam', 'Party / Night', NULL, NULL, 'https://officialmykonos.com/products/mykonos-aphrodite-extrait-de-parfum-50ml-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Jasmine, Burnt Cinnamon, Myrrh Middle Notes: Cedarwood, Tonka Bean, Sandalwood Base Notes: White Musk, Tobacco, Vanilla, Mineral Amber No BPOM : NA18240607827', 'Cedarwood, Tonka Bean, Sandalwood Base Notes: White Musk, Tobacco, Vanilla, Mineral Amber No BPOM : NA18240607827', 'White Musk, Tobacco, Vanilla, Mineral Amber No BPOM : NA18240607827', 'Woody, Floral, Oriental, Gourmand', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Dekat (Skin Scent)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Baby Love EDP 50ml', 'Mykonos', 'Mykonos - Baby Love EDP 50ml A blast from the past, and a luxurious remake of baby cologne for adults. A reminder of a nostalgic and innocent childhood. The scent of fresh florals, soft musk, and that ultimate baby scent. The tender nature of this masterpiece makes it perfect for use anywhere and anytime, even at home! Top Notes: Violet, Musk, Rose Middle Notes: Violet, Rose Base Notes: Violet, Musk No : NA18210600379', NULL, 29900000.0, 'Unisex', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-baby-love-edp-50ml', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Violet, Musk, Rose Middle Notes: Violet, Rose Base Notes: Violet, Musk', 'Violet, Rose Base Notes: Violet, Musk', 'Violet, Musk', 'Floral, Oriental, Fresh', 'Musim Semi', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Berry Caramel Pancake EDP 50ml', 'Mykonos', 'Mykonos - Berry Caramel Pancake EDP 50ml What�s better than pancakes for breakfast on a Sunday morning? Pancakes with fresh berries drizzled with your favourite caramel syrup, of course! Indulge in the smoky sweetness of decadent caramel sauce drizzled on the fluffiest buttery pancakes, topped with freshly picked berries and cold whipped cream. Smell like the most delicious dessert, make them want a piece of you. Top Notes: Mixed Berry Coulis, Brown Sugar, Lemon Middle Notes: Smoked Brown Sugar Caramel, Butter Pancake Bottom Notes: Caramel, Blackberry, Cashmere Wood, Tonka Bean No. : NA18220602880', NULL, 29900000.0, 'Unisex', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-berry-caramel-pancake-edp-50ml', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Mixed Berry Coulis, Brown Sugar, Lemon Middle Notes: Smoked Brown Sugar Caramel, Butter Pancake Bottom Notes: Caramel, Blackberry, Cashmere Wood, Tonka Bean No', 'Smoked Brown Sugar Caramel, Butter Pancake Bottom Notes: Caramel, Blackberry, Cashmere Wood, Tonka Bean No', 'Caramel, Blackberry, Cashmere Wood, Tonka Bean No', 'Woody, Citrus, Fresh, Gourmand', 'Musim Dingin', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Black Opera Extrait de Parfum 100ml', 'Mykonos', 'Mykonos - Black Opera Extrait de Parfum 100ml An addictive blend of bold coffee, sensual vanilla, and charismatic jasmine. Charming, mysterious, desirable, intoxicating, you can�t get it off your mind. Black Opera is an intense, luscious, and seductive scent. So intense, it makes the heads of those who smell it spin. It�s powerful yet ever so delicate. A cup of coffee and a bouquet of sweet, fragrance white florals, with a touch of earth and hint of wood. Your reality will feel like a hallucination with just one spray. It feels young, playful, but not childish. The perfect balance between sexy and sweet. Black Opera is a scent you don�t just wear anywhere', NULL, 200000.0, 'Pria', 'Malam', 'Date / Romantic', NULL, NULL, NULL, 0.0, 0.0, 'Extrait de Parfum', 'Vanilla, Orange Blossom, Pink Pepper Middle Notes: Licorice, Jasmine, Almond, Coffee Base Notes: Cashmere wood, Jasmine, Vanilla, Patchouli No', 'Licorice, Jasmine, Almond, Coffee Base Notes: Cashmere wood, Jasmine, Vanilla, Patchouli No', 'Cashmere wood, Jasmine, Vanilla, Patchouli No', 'Woody, Floral, Citrus, Oriental', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Sangat Kuat (Loud)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Body Mist 115ML', 'Mykonos', 'Matcha Sundays Body Mist 115ml Matcha Sundays is a calming blend of matcha and osmanthus with a twist of florals and mint, giving off a zen and relaxed vibe. For those who love green and clean scent as it is the perfect scent for a lazy sunday at home, very cozy and comfy. It�s like drinking hot matcha while blending in with nature, admiring the view while you sip on your cup of tea. Personality Traits: Calm, Composed, Learned, Intelligent, Soft-spoken Main Notes: Matcha, Osmanthus, Jasmine, Mint, A Hint of Milk No. : NA18230603110 ------------------------------------------------------------------------------------------------ Love Rosy Body Mist 115ml Love Rosy is a fresh and sparkling blend of roses and chamomile, creating a very romantic and classy scent, like that giddy feeling of watching a super romantic romcom movie. It smells elegant, rich, and unique, made for all you hopeless romantics. Personality Traits: Romantic, Compassionate, Sweet, Loveable Main Notes: Rose, Pink Pepper, Chamomile, Amber No. : NA18220603257 -------------------------------------------------------------------------------------------------- Lychee Breeze Body Mist 115ml Lychee Breeze is a sweet and rejuvenating blend of lychee and black tea. As refreshing as a glass of iced lychee tea on a hot, sunny day. Juicy, fresh and very upbeat. Personality Traits: Cheerful, Life of the Party, Happy, Extrovert Main Notes: Lychee, Mint, Black Tea, Brown Sugar No. : NA18230603111', NULL, 9900000.0, 'Pria', 'Pagi / Siang', 'Date / Romantic', NULL, NULL, 'https://officialmykonos.com/products/mykonos-body-mist-115ml', 0.0, 0.0, 'Body Mist', 'Pink Pepper, Mint', 'Jasmine, Osmanthus, Rose', 'Amber', 'Floral, Oriental, Fresh, Gourmand', 'Musim Panas', 'Sedang (2-4 jam)', 'Sedang (Moderate)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Bonfire Vanilla Extrait de Parfum 50ml', 'Mykonos', 'Mykonos - Bonfire Vanilla Extrait de Parfum 50ml Have you ever dreamt of the warm feeling of biting into smores roasted on a campfire against a cold winter? Picture this: You�re dressed in a sexy black dress, ready for a festive dinner, but it''s snowing outside, yet you feel so warm sitting by the campfire, snuggling under fuzzy blankets, whilst roasting vanilla marshmallows with a loved one. Bonfire vanilla is a smoky blend of Wood fire, sweet spices, brown suga, and roasted vanilla. An extrait de parfum that will last all day on your skin, A scent that starts off spicy and strong, but dries down cozy and warm. Top Notes: Cloves, Nutmeg, Pink Pepper, Orange Zest, Vanilla Middle Notes: Smoked Wood, Pepper, Guaiac Wood, Burnt Brown Sugar Base Notes: Smoked Wood, Vanilla, Marshmallow, Caramel No : NA18220603948', NULL, 29900000.0, 'Unisex', 'Pagi / Siang', 'Date / Romantic', NULL, NULL, 'https://officialmykonos.com/products/mykonos-bonfire-vanilla-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Cloves, Nutmeg, Pink Pepper, Orange Zest, Vanilla Middle Notes: Smoked Wood, Pepper, Guaiac Wood, Burnt Brown Sugar Base Notes: Smoked Wood, Vanilla, Marshmallow, Caramel No BPOM : NA18220603948', 'Smoked Wood, Pepper, Guaiac Wood, Burnt Brown Sugar Base Notes: Smoked Wood, Vanilla, Marshmallow, Caramel No BPOM : NA18220603948', 'Smoked Wood, Vanilla, Marshmallow, Caramel No BPOM : NA18220603948', 'Woody, Citrus, Oriental, Gourmand', 'Musim Dingin', 'Sangat Tahan Lama (8+ jam)', 'Sangat Kuat (Loud)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Cafe Drops Extrait de Parfum 50ml', 'Mykonos', 'Mykonos - Cafe Drops Extrait de Parfum 50ml This carton of milk contains comfort and sophistication. Cafe Drops is a captivating fragrance that evokes the warmth of a cozy cafe and the elegance of a leisurely afternoon. Imagine the rich aroma of warm vanilla milk, freshly brewed and simmered to creamy perfection. A touch of coffee peeks through, adding a subtle depth and a hint of grown-up intrigue. Like a perfect cup of tiramisu, Caf� Drops is both sweet and sophisticated, playful and undeniably classy. It is the fragrance for those who appreciate the finer things in life, who savor the simple pleasures, and who exude a timeless elegance. Let Caf� Drops linger on your skin, leaving a trail of intrigue and a touch of sweetness that''s both inviting and unforgettable. Top Notes: Orchid, Jasmine, Coffee Middle Notes: Vanilla, Caramel, Tonka Bean, Milk Base Notes: Amber, Musk, Wood, Patchouli No. : NA18240605661', NULL, 29900000.0, 'Unisex', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-cafe-drops-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Orchid, Jasmine, Coffee Middle Notes: Vanilla, Caramel, Tonka Bean, Milk Base Notes: Amber, Musk, Wood, Patchouli No', 'Vanilla, Caramel, Tonka Bean, Milk Base Notes: Amber, Musk, Wood, Patchouli No', 'Amber, Musk, Wood, Patchouli No', 'Woody, Floral, Oriental, Fresh', 'Musim Dingin', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - California Blue Extrait de Parfum 50ml & 100ml', 'Mykonos', 'California Blue Extrait de Parfum 50ml & 100ml The essence of playful freedom, California Blue captures the feeling of a bright, sunlit day at the beach, where the salty ocean breeze mingles with the playful energy of laughter and adventure. A burst of juicy pear, grapefruit, and pink salt mirrors the thrill of the first dive into cool waves, while rhubarb and water blossoms carry the carefree spirit of sun-kissed fun. The scent settles into a comforting blend of softwood, moos, and caramel, reminiscent of golden beach sunsets. This is the fragrance for the free-spirited drifter, someone who finds joy in the ocean''s embrace and lives for spontaneous moments of adventure and excitement. Lighthearted, fruity, fresh, and aquatic. California Blue embodies the soul of summer and the endless call of the waves. Top Notes: Lavender, Pear, Grapefruit, Pink Salt Middle Notes: Rhubarb, Water Blossoms, Marine Notes Base Notes: Moss, Softwood, Caramel No. : NA18250600809', NULL, 29900000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-california-blue-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Lavender, Pear, Grapefruit, Pink Salt', 'Rhubarb, Water Blossoms, Marine Notes', 'Moss, Softwood, Caramel', 'Woody, Fresh, Gourmand, Aromatic', 'Musim Panas', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - California Club Extrait de Parfum 50ml', 'Mykonos', 'California Club Extrait de Parfum 50ml The Sophisticated Night by The Sea As the sun dips below the horizon and the ocean glows under moonlight, California Club emerges. A fragrance inspired by the intoxicating allure of a seaside nightclub. The metallic tinge of the ocean breeze mixes with a refined blend of marine notes, giving an edge of mystery and sophistication. At the heart of California Club that truly defines its nighttime elegance. The deep floral richness of rose, iris, and violet brings an unexpected depth, adding an intoxicating, almost velvety allure. These middle notes weave together, creating a fragrance that is both bold and refined, a scent that unfolds as the night progresses. California Club is for the modern sophisticate who enjoys the finer things in life. A scent that is more formal, collected, and effortlessly cool, it''s made for nights of confidence, conversation, and oceanfront glamour. Top Notes: Bergamot, Lemon, Violet Leaf Middle Notes: Rose, Violet, Iris Base Notes: Amberwood, Ambrette, Sandalwood No. : NA18250602293', NULL, 29900000.0, 'Unisex', 'Malam', 'Office / Formal', NULL, NULL, 'https://officialmykonos.com/products/mykonos-california-club-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Bergamot, Lemon, Violet Leaf', 'Rose, Violet, Iris', 'Amberwood, Ambrette, Sandalwood', 'Woody, Floral, Citrus, Oriental', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Sangat Kuat (Loud)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - California Extrait de Parfum 50ml & 100ml', 'Mykonos', 'California Signature Extrait de Parfum 50ml & 100ml Savoring a boujee, carefree summer vacation in California. Freshness of aromatic citrus and aquatic notes greet your nose on first whiff giving a fresh, crisp beachside atmosphere. As the scent unfolds, a subtle nuance of lavender begins to emerge, adding a touch of sophistication to the fragrance. As time goes by, it keeps radiating summery freshness complimented by a lush sweetness from the scent of juicy lychee margaritas. It creates a seductive and inviting summer impression with an exotic twist. In the base, Teak wood and vetiver beautifully cut through the freshness of California, giving a classic and gentle reminder of old wealth, an incredibly sensual and sophisticated impression. Top Notes: Mandarin Orange, Lemon Middle Notes: Lychee, Rosemary, Cardamom, Lavender, Geranium, Aquatic Notes Base Notes: Tonka Bean, Teak Wood, Vetiver No. : NA18230605923', NULL, 29900000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-california-signature-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Mandarin Orange, Lemon', 'Lychee, Rosemary, Cardamom, Lavender, Geranium, Aquatic Notes', 'Tonka Bean, Teak Wood, Vetiver', 'Woody, Floral, Citrus, Fresh', 'Musim Panas', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Caramel Fudge Cookie EDP 50ml', 'Mykonos', 'Mykonos - Caramel Fudge Cookie EDP 50ml The scent of the most delicious soft baked chocolate chip cookies filled with gooey, buttery caramel. Imagine taking your first bite into the sweetness of vanilla-infused soft cookies with chunks of melted chocolate. As you keep biting into your cookie, you feel a hint of saltiness from sea salt, giving your cookie a beautiful balance of flavors, and as you get to the center of your cookie you bite into what we''d say is the most delightful feeling of gooey smoked, buttery caramel. Feels delicious, doesn''t it? Now imagine smelling just like this cookie, how irresistible would you be! And the best part, it''s O calories! Top Notes: Cookie Dough, Caramel, Vanilla Middle Notes: Caramel, Condensed Milk, Sea Salt Base Notes: White Musk, Vanilla, Caramel, Praline No. : NA18230600397', NULL, 29900000.0, 'Unisex', 'Malam', 'Date / Romantic', NULL, NULL, 'https://officialmykonos.com/products/mykonos-caramel-fudge-cookie-edp-50ml', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Cookie Dough, Caramel, Vanilla Middle Notes: Caramel, Condensed Milk, Sea Salt Base Notes: White Musk, Vanilla, Caramel, Praline No', 'Caramel, Condensed Milk, Sea Salt Base Notes: White Musk, Vanilla, Caramel, Praline No', 'White Musk, Vanilla, Caramel, Praline No', 'Oriental, Gourmand', 'Musim Gugur', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Coconut Dreams Extrait de Parfum 50ml', 'Mykonos', 'Mykonos - Coconut Dreams EDP 50ml A creamy, decadent, nutty vanilla fragrance that is NOT your typical tropical summer fragrance. The story of a memorable sunset at the beach. A tropical gourmand scent that feels exotic and indulgent. Sweet, creamy coconut meets gourmand vanilla and fresh florals, reminiscent of rich coconut ice cream sprinkled with vanilla sugar on a beautiful white sand beach under the vanilla skies during sunset. Top Notes: Coconut, Aloe Vera, Lily of the Valley Middle Notes: C oconut cream, Vanilla, Sweet Rice Base Notes: Vanilla, Cashmere Wood No. : NA18240607828', NULL, 29900000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-coconut-dreams-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Coconut, Aloe Vera, Lily of the Valley Middle Notes: C oconut cream, Vanilla, Sweet Rice Base Notes: Vanilla, Cashmere Wood No', 'C oconut cream, Vanilla, Sweet Rice Base Notes: Vanilla, Cashmere Wood No', 'Vanilla, Cashmere Wood No', 'Woody, Floral, Oriental, Fresh', 'Musim Panas', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Conquer Extrait de Parfum 50ml & 100ml', 'Mykonos', 'Conquer Extrait de Parfum 100ml Conquer opens with a surge of bergamot, sharpened by ginger and cardamom a fresh, electrifying beginning that sets everything in motion. As the intensity unfolds, orris and orange blossom rise at the core, bringing a refined floral depth that feels composed, deliberate, and quietly powerful. The story deepens as earthy patchouli merges with clean musks, modern amber, and a subtle touch of vanilla, setting into a warm, frounded trail that lingers long after the moment has passed. This is a fragrance built on momentum confident, controlled, and unwavering. This fragrance was never meant to be loud. it was meant to Conquer. Notes : Top Notes : Bergamot, Ginger, Cardamom Middle Notes : Orris, Orange Blossom Base Notes : Patchouli, Musk, Modern Amber, Vanilla No : NA18260600178', NULL, 49900000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-conquer-extrait-de-parfum-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Bergamot, Ginger, Cardamom', 'Orris, Orange Blossom', 'Patchouli, Musk, Modern Amber, Vanilla', 'Woody, Floral, Citrus, Oriental', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Sangat Kuat (Loud)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Crimson Extrait de Parfum 100ml', 'Mykonos', 'CRIMSON Extrait de Parfum 100ml Crimson is a story of contrast, where brightness meets depth, and sweetness meets skin. It opens with Poached Peach Cr�me and Cherry Nectar dripping in sweetness, brightened by a soft lift of Bergamot. In the heart, Geranium Petals and Jasmine Absolute unfold with quiet elegance, wrapped in a silky Caramel Cr�me accord that melts into the skin. As it settles, Patchouli Madagascar, Honeyed Amber, and White Musk create a warm, glowing trail � smooth, intimate, and irresistibly addictive. A scent that lingers like a slow touch. Creamy. Radiant. Magnetic. Top Notes : Poached Peach Creme, Cherry Nectar, Bergamot Middle Notes : Geranium Petals, Caramel Creme Accord, Jasmine Absolute Base Notes : Patchouli Madagascar, Honeyed Amber, White Musk No : NA18250611826', NULL, 49900000.0, 'Unisex', 'Pagi / Siang', 'Date / Romantic', NULL, NULL, 'https://officialmykonos.com/products/mykonos-crimson-extrait-de-parfum-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Poached Peach Creme, Cherry Nectar, Bergamot Middle Notes : Geranium Petals, Caramel Creme Accord, Jasmine Absolute Base Notes : Patchouli Madagascar, Honeyed Amber, White Musk No BPOM : NA18250611826', 'Geranium Petals, Caramel Creme Accord, Jasmine Absolute Base Notes : Patchouli Madagascar, Honeyed Amber, White Musk No BPOM : NA18250611826', 'Patchouli Madagascar, Honeyed Amber, White Musk No BPOM : NA18250611826', 'Woody, Floral, Citrus, Oriental', 'Musim Gugur', 'Sangat Tahan Lama (8+ jam)', 'Dekat (Skin Scent)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Dark Secret Extrait de Parfum 100ml', 'Mykonos', 'Mykonos - Dark Secret Extrait de Parfum 100ml Dark Secret unveils the seductive dance of spiced cherries, rich saffron, decadent praline, and mystical woods, an olfactory journey that takes you to a place where sweetness meets darkness, entwined with mystique. A scent that whispers tales only the night knows. A fragrance that speaks of hidden desires, evokes timeless elegance, and leaves an indelible impression. Top Notes : Black Cherry, Saffron, Bergamot Middle Notes: Cinnamon, Nutmeg, Marigold, Jasmine, Praline Base Notes: Amber, Musk, Tonka Bean, Sandalwood No. : NA18230606514', NULL, 49900000.0, 'Unisex', 'Malam', 'Party / Night', NULL, NULL, 'https://officialmykonos.com/products/mykonos-dark-secret-extrait-de-parfum-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Black Cherry, Saffron, Bergamot Middle Notes: Cinnamon, Nutmeg, Marigold, Jasmine, Praline Base Notes: Amber, Musk, Tonka Bean, Sandalwood No', 'Cinnamon, Nutmeg, Marigold, Jasmine, Praline Base Notes: Amber, Musk, Tonka Bean, Sandalwood No', 'Amber, Musk, Tonka Bean, Sandalwood No', 'Woody, Floral, Citrus, Oriental', 'Musim Gugur', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Dreamscape Extrait de Parfum 50ml & 100ml', 'Mykonos', 'Dreamscape Extrait de Parfum 50ml & 100ml Dreamscape is a scent that feels like a dream you don�t want to wake up from. It starts with a mouthwatering mix of ripe mango, citrus and red berries, juicy, bright, and irresistibly addictive. As it settles, soft jasmine, warm cedarwood, and a hint of sweetness from coumarin begin to shine through. In the end, it dries down to a cozy blend of musk, woods, and amber. Addictive and comforting, Dreamscape leaves a lasting impression, a hypnotic glow that stays with you long after the moment has passed. It''s more than a fragrance, it''s a vivid escape. Top Notes: Mango, Italian Lemon, Rhubarb Middle Notes: Ginger, Jasmine, Violet, Praline, Pink Pepper Base Notes: Cedar, Grey Amber, Tonka Beans, Moss No. : NA18250605476', NULL, 29900000.0, 'Pria', 'Pagi / Siang', 'Office / Formal', NULL, NULL, 'https://officialmykonos.com/products/mykonos-dreamscape-extrait-de-parfum-50ml-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Mango, Italian Lemon, Rhubarb Middle Notes: Ginger, Jasmine, Violet, Praline, Pink Pepper Base Notes: Cedar, Grey Amber, Tonka Beans, Moss', 'Ginger, Jasmine, Violet, Praline, Pink Pepper Base Notes: Cedar, Grey Amber, Tonka Beans, Moss', 'Cedar, Grey Amber, Tonka Beans, Moss', 'Woody, Floral, Citrus, Oriental', 'Musim Dingin', 'Sangat Tahan Lama (8+ jam)', 'Dekat (Skin Scent)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Enchanted Extrait de Parfum 50ml & 100ml', 'Mykonos', 'Mykonos - Enchanted Extrait de Parfum 50ml & 100ml Immerse yourself in the most magical blend of fresh florals, A scent that transports you into a fairytale...somewhere in the meadows, Where you''re surrounded by dewy bouquets of roses and peonies. Sparkling notes of bright citrus compliment this scent beautifully Just like the feeling of warm sunlight shining on your face as you lay down on a bed of flowers in the meadows. Yes, this scent is meant to make you feel like a princess, But this time, you''re no ordinary princess You''re sophisticated and charming, yet bold and brilliant, You''re a princess with a statement, Enchant them with your confidence, Bloom wherever you go. Top Notes: Mandarin Orange Middle Notes: Peony, Rose, Violet, Peach Base Notes: Iris, Musk No. : NA18220603947', NULL, 29900000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, 'https://officialmykonos.com/cdn/shop/files/enchanted_50ml_sku_2_1.jpg?v=1779432612&width=1240', 'https://officialmykonos.com/products/mykonos-enchanted-extrait-de-parfum-50ml-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Mandarin Orange Middle Notes: Peony, Rose, Violet, Peach Base Notes: Iris, Musk No', 'Peony, Rose, Violet, Peach Base Notes: Iris, Musk No', 'Iris, Musk No', 'Floral, Citrus, Oriental, Fresh', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Sangat Kuat (Loud)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Hawaiian Crush Extrait de Parfum 50ml', 'Mykonos', 'Mykonos - Hawaiian Crush Extrait de Parfum 50ml An artful explosion of the senses that transports you to the enchanting landscapes of Hawaii. Embrace the beauty of contrast where the first whiff bursts with vibrancy and the last sniff unravels a depth of mystery. Envision yourself in a sun-drenched orchard in the first whiff, where the sweetness of ripe, juicy lychee meets enticing black tea. At the heart, the fragrance unfolds delicate whispers of rose and lily of the valley setting the image of a lush Hawaiian garden, where soft petals shimmer in the setting sun. At its dry down, Hawaiian Crush reveals its magic on Hawaii''s shores, where crimson and gold ignite the sky. Amidst the breeze, the scent transforms into a sensuous blend of velvety musk and intoxicating incense, evoking the romance, passion, and mystique of a Hawaiian sunset. A scent that truly feels like an abstract painting in a bottle. Top notes : Lychee, Red Fruits, Black Tea Middle notes : Rose, Lily Of The Valley, Lychee, Black tea Bottom notes : Amber, Patchouli, Musk, Incense No. : NA18240603918', NULL, 29900000.0, 'Pria', 'Seharian', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-hawaiian-crush-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Lychee, Red Fruits, Black Tea Middle notes : Rose, Lily Of The Valley, Lychee, Black tea Bottom notes : Amber, Patchouli, Musk, Incense No', 'Rose, Lily Of The Valley, Lychee, Black tea Bottom notes : Amber, Patchouli, Musk, Incense No', 'Amber, Patchouli, Musk, Incense No', 'Woody, Floral, Oriental, Gourmand', 'Musim Gugur', 'Sangat Tahan Lama (8+ jam)', 'Dekat (Skin Scent)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Inception Extrait de Parfum 50ml & 100ml', 'Mykonos', 'Inception Extrait de Parfum 50ml & 100ml The fragrance begins with the sharp clarity of Bergamot, Ginger, and bright citrus notes, instantly awakening the senses. A warm fusion of Neroli, Cinnamon, Black Tea, and Biga Flower forms the heart, blending spice, florals, and tea into a modern aromatic core. In the dry down, Guaiac, Musk, Cedarwood, and Lorenox� create a deep, woody finish that feels grounded, smooth, and confidently refined. Top Notes : Bergamot, Ginger, Orange, Lemon Middle Notes : Neroli, Cinnamon, Black Tea, Biga Flower Base Notes : Guaiac, Musk, Cedarwood, LorenoxTM No : NA18250611824', NULL, 29900000.0, 'Unisex', 'Pagi / Siang', 'Office / Formal', NULL, NULL, 'https://officialmykonos.com/products/mykonos-inception-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Bergamot, Ginger, Orange, Lemon Middle Notes : Neroli, Cinnamon, Black Tea, Biga Flower Base Notes : Guaiac, Musk, Cedarwood, LorenoxTM No BPOM : NA18250611824', 'Neroli, Cinnamon, Black Tea, Biga Flower Base Notes : Guaiac, Musk, Cedarwood, LorenoxTM No BPOM : NA18250611824', 'Guaiac, Musk, Cedarwood, LorenoxTM No BPOM : NA18250611824', 'Woody, Floral, Citrus, Oriental', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Luminos Extrait de Parfum 50ml', 'Mykonos', 'Luminos Extrait de Parfum 50ml THE FIRST EVER GLOW IN THE DARK FRAGRANCE INFUSED WITH OUR VERY OWN, BLUE JAVA BANANA ACCORD. Luminos Shines as �A Celebration of the Light Within Us All� that often goes unnoticed. With creamy, floral, woody notes, and a unique blue java banana accord, Luminos encourages you to illuminate the world with your inner brilliance, reminding you that "You Are More Than What Meets The Eye". Top Notes : Apple, Banana (Part of The Blue Java Banana Accord) Middle Notes : White Florals, Rose, Tuberose, Lily of The Valley, Orange Blossom, Vanilla (Part of The Blue Java Banana Accord) Base Notes : Amber, Edible Notes, Solar Accord, Amberwood, Cashmere, Ice Cream (Part of The Blue Java Banana) No. : NA18240608244', NULL, 29900000.0, 'Unisex', 'Seharian', 'Party / Night', NULL, NULL, 'https://officialmykonos.com/products/mykonos-luminos-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Apple, Banana (Part of The Blue Java Banana Accord)', 'White Florals, Rose, Tuberose, Lily of The Valley, Orange Blossom, Vanilla (Part of The Blue Java Banana Accord)', 'Amber, Edible Notes, Solar Accord, Amberwood, Cashmere, Ice Cream (Part of The Blue Java Banana)', 'Woody, Floral, Citrus, Oriental', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Dekat (Skin Scent)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Matcha Latte Extrait de Parfum 50ml', 'Mykonos', 'Mykonos - Matcha Latte Extrait de Parfum 50ml A calming blend of matcha and white chocolate with a twist of florals and a hint of mint. This intoxicating blend smells great all day long and gives off a zen and relaxed vibe, the perfect scent for a lazy sunday at home. Main Notes: Matcha, White Chocolate, Jasmine, Tonka Bean, Vanilla, Milk Powder No. : NA18220603949', NULL, 29900000.0, 'Unisex', 'Pagi / Siang', 'Date / Romantic', NULL, NULL, 'https://officialmykonos.com/products/mykonos-matcha-latte-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Mint', 'Jasmine', 'Tonka, Vanilla', 'Floral, Oriental, Gourmand, Aromatic', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Kuat (Moderate-Heavy)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Mayfair Extrait de Parfum 100ml', 'Mykonos', 'Mayfair Extrait de Parfum 100ml Mayfair is a polished expression of modern heirloom luxury. A fragrance that feels established, not nostalgic. Bright bergamot and orange open with composed freshness, wrapped in a subtle smoky edge. A restrained touch of raspberry adds depth to the citrus, giving it weight and maturity rather than sweetness. At the heart, caramel melts seamlessly into lavender and jasmine, creating a smooth, controlled warmth that feels curated, never indulgent. As it settles, layered woods, supple leather, patchouli, and sandalwood form a deep, elegant base, leaving a smoky, leather trail that feels grounded, assured, and effortlessly sophisticated. This is not a statement piece. It�s legacy, worn effortlessly.Top Notes: Bergamot, Orange, Raspberry Middle Notes: Caramel, Lavender, Jasmine Base Notes: Wood, Leather, Patchouli, Sandalwood No : NA18260601433', NULL, 49900000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-mayfair-extrait-de-parfum-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Bergamot, Orange, Raspberry Middle Notes: Caramel, Lavender, Jasmine Base Notes: Wood, Leather, Patchouli, Sandalwood No BPOM : NA18260601433', 'Caramel, Lavender, Jasmine Base Notes: Wood, Leather, Patchouli, Sandalwood No BPOM : NA18260601433', 'Wood, Leather, Patchouli, Sandalwood No BPOM : NA18260601433', 'Woody, Floral, Citrus, Fresh', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Milk Drops Extrait de Parfum 50ml', 'Mykonos', 'Mykonos - Milk Drops Extrait de Parfum 50ml This carton of milk contains a whimsy of innocence and cuddle-worthy charms. A fragrance that seamlessly blends velvety softness of creamy milk with the tender embrace of white musk. A nostalgic trip to childhood, where innocence reigns, and memories are as sweet as a mother''s lullaby. A spritz of Milk Drops for a hug of comfort and a journey back to the heartwarming days of yesteryear! No animals were harmed in the creation of fragrance. PS: Meet our Baby Cow! So cute, it could make clouds jealous~ Top Notes : Floral Bouquet, Milk Middle Notes : Milk, Green Notes Base Notes : Tonka Bean, White Musk, White Wood No. : NA18240601779', NULL, 29900000.0, 'Unisex', 'Pagi / Siang', 'Date / Romantic', NULL, NULL, 'https://officialmykonos.com/products/mykonos-milk-drops-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Floral Bouquet, Milk Middle Notes : Milk, Green Notes Base Notes : Tonka Bean, White Musk, White Wood No', 'Milk, Green Notes Base Notes : Tonka Bean, White Musk, White Wood No', 'Tonka Bean, White Musk, White Wood No', 'Woody, Floral, Oriental, Gourmand', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Sangat Kuat (Loud)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Monaco Royale Extrait de Parfum 50ml & 100ml', 'Mykonos', 'Mykonos - Monaco Royale Extrait de Parfum 50ml & 100ml Monaco Royale is a fragrance of contrasts�fresh and breezy yet deep and sensual. It opens with fresh and crisp notes of melon, pear, and green accords, evoking the breezy elegance of the French Riviera. The heart reveals warm cedarwood, adding depth and refinement. It dries down to a luxurious blend of caramel, musk, and moss, exuding sophistication of a romantic night in Monaco. A perfect balance of radiant freshness and sensual allure. Top Notes: Pear, Melon, Green Notes Middle Notes: Soft Wood, Cedarwood Base Notes: Moss, Caramel, Musk No. : NA18240609900, NA18240609900', NULL, 29900000.0, 'Pria', 'Pagi / Siang', 'Date / Romantic', NULL, NULL, 'https://officialmykonos.com/products/mykonos-monaco-royale-extrait-de-parfum-50ml-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Pear, Melon, Green Notes Middle Notes: Soft Wood, Cedarwood Base Notes: Moss, Caramel, Musk No', 'Soft Wood, Cedarwood Base Notes: Moss, Caramel, Musk No', 'Moss, Caramel, Musk No', 'Woody, Oriental, Fresh, Gourmand', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Moroccan Vanilla Extrait de Parfum 100ml', 'Mykonos', 'Mykonos - Moroccan Vanilla Extrait de Parfum 100ml An exotic blend of turkish rose, creamy vanilla, and sensual wood. The story of a casual romance in a Moroccan desert during sunset, laying under the pink skies, sharing a sip of spiced rose-vanilla tea. Indulge in the most luxurious scent of turkish roses, blended with warm vanilla, spicy cinnamon, fresh lemon, and rich cedarwood. A golden juice that suits beautifully on your skin. Moroccan Vanilla personifies romance on the sand dunes', NULL, 200000.0, 'Pria', 'Pagi / Siang', 'Casual / Daily', NULL, NULL, NULL, 0.0, 0.0, 'Extrait de Parfum', 'Moroccan Vanilla, Bulgarian Rose, Rose, Lemon Middle Notes: Bulgarian Rose, Vanilla, Lemon, Sugar Base Notes: White Musk, Sugar, Vanilla No', 'Bulgarian Rose, Vanilla, Lemon, Sugar Base Notes: White Musk, Sugar, Vanilla No', 'White Musk, Sugar, Vanilla No', 'Woody, Floral, Citrus, Oriental', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Musk Aura Extrait de Parfum 100ml', 'Mykonos', 'Mykonos - Musk Aura Extrait de Parfum 100ml An ode to the beauty and sensuality of �Musks�. Musk Aura is an enchanting fragrance that combines the allure of delicate rose and jasmine with the irresistible sensuality of musk. Specially crafted to capture the essence of island evenings, where the warm tropical breeze carries the intoxicating aroma of blooming flowers, setting the stage for intimate encounters and unforgettable moments of romance and seduction. Heady notes of florals intertwine with the fresh and lively essence of sweet apples, creating an aura of femininity and grace. The base notes anchor the fragrance with the allure of musk. A blend of velvety white musk and subtle hints of amber and nectarine create a seductive foundation that wraps you in a warm and intimate embrace. Musk Aura is the embodiment of seduction and passion under the stars. It''s the perfect companion for evenings spent on a secluded beach or dancing under the moonlight. Top Notes: Bergamot, Yuzu, Apple Middle Notes: Lily of the Valley, Sambac Jasmine, Ylang-ylang Base Notes: Amber, Musk, Citrus, Nectarine No. : NA18230604097', NULL, 49900000.0, 'Pria', 'Pagi / Siang', 'Date / Romantic', NULL, NULL, 'https://officialmykonos.com/products/mykonos-musk-aura-extrait-de-parfum-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Bergamot, Yuzu, Apple Middle Notes: Lily of the Valley, Sambac Jasmine, Ylang-ylang Base Notes: Amber, Musk, Citrus, Nectarine No', 'Lily of the Valley, Sambac Jasmine, Ylang-ylang Base Notes: Amber, Musk, Citrus, Nectarine No', 'Amber, Musk, Citrus, Nectarine No', 'Floral, Citrus, Oriental, Fresh', 'Musim Panas', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - On The Rocks Extrait de Parfum 100ml', 'Mykonos', 'Mykonos - On The Rocks Extrait de Parfum 100ml "I want something sweet, boozy, aromatic, and bold... but make it On The Rocks." Like a perfectly crafted cocktail, On The Rocks stirs unexpected contrasts into an intoxicating blend. The first spritz is a crisp splash of bergamot and apple, fresh and invigorating, before the rich depth of myrrh swirls in�smooth, warm, and seductively bold, like an amber liquor poured slow. As the scent settles, the smoky elegance of guaiacwood and the floral sensuality of orange flower unfold, while a hint of praline lingers like the lingering sweetness of an irresistible sip. Finally, vanilla and ambroxan melt into the skin, wrapping you in a trail that�s both sultry and dangerously smooth�the scent of a night you�ll never forget. Crisp yet deep. Smooth yet daring. Indulgent yet refined. This is your dream drink, bottled. One spritz, and you�re hooked. Top Notes: Bergamot, Apple, Myrrh Middle Notes: Orange Flower, Guiacwood, Praline Base Notes: Vanilla, Ambroxan, Praline No. : NA18250601160', NULL, 49900000.0, 'Unisex', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-on-the-rocks-extrait-de-parfum-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Bergamot, Apple, Myrrh Middle Notes: Orange Flower, Guiacwood, Praline Base Notes: Vanilla, Ambroxan, Praline No', 'Orange Flower, Guiacwood, Praline Base Notes: Vanilla, Ambroxan, Praline No', 'Vanilla, Ambroxan, Praline No', 'Woody, Floral, Citrus, Oriental', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Sangat Kuat (Loud)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Paradise Extrait de Parfum 50ml', 'Mykonos', 'Mykonos - Paradise Extrait de Parfum 50ml When Cuba meets Bali. It''s a sunny afternoon, you''re sipping on a glass of ice cold pina colada by the pristine turquoise Caribbean seas whilst being surrounded by fragrant Balinese frangipani trees. The top notes set the stage for a tropical holiday with a wide range of tangy fruits. Tropical, bright, refreshing, and juicy with a touch of sensual creaminess from coconut. The fragrance beautifully transitions into a creamy floral sensation, highlighting white floral nuances. The creaminess from coconut lingers on and enhances the sweetness of frangipani flowers and freshness of jasmine. The dry down is calming, therapeutic, and sensual while the fruits leave a subtle trail of brightness. Top Notes: Coconut, Mandarin Orange, Pear, Pineapple Middle Notes: Frangipani, Jasmine, Lily Base Notes: Amber, Vanilla, Woody No. : NA18240607826', NULL, 29900000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-paradise-extrait-de-parfum-50ml', 0.0, 0.0, 'Extrait de Parfum', 'Coconut, Mandarin Orange, Pear, Pineapple Middle Notes: Frangipani, Jasmine, Lily Base Notes: Amber, Vanilla, Woody No', 'Frangipani, Jasmine, Lily Base Notes: Amber, Vanilla, Woody No', 'Amber, Vanilla, Woody No', 'Woody, Floral, Citrus, Oriental', 'Musim Panas', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Mykonos - Penthouse Extrait de Parfum 50ml & 100ml', 'Mykonos', 'Penthouse Extrait de Parfum 50ml & 100ml Penthouse is the scent of a luxurious bath. It�s clean, soft, and quietly indulgent. It opens with Sparkling Blackcurrant, airy Aldehydes, Mandarin Zest, and a gentle Rose Mist that feels like fresh water hitting your skin. At the heart, Velvety White Florals, White Tea Vapor, and a White Soap Accord build that immaculate, �fresh-from-the-shower� glow, wrapped in the refined warmth of Cashmere Wood and Cedarwood. As it dries down, Tonka Foam, Iso E Super, Amber, Clean Musks, and Cashmeran melt into the skin like the lingering warmth after a long, lush bath. Clean. Soapy. Luminous. Top Notes : Sparkling Blackcurrant, Aldehydes, Mandarin Zest, Rose Mist Middle Notes : Velvety White Floral, White Tea Vapor, White Soap Accord, Cashmere Wood. Cedarwood Base Notes : Tonka Foam, Iso E Super, Amber, Clean Musks, Cashmeran No : NA18250611825', NULL, 29900000.0, 'Pria', 'Pagi / Siang', 'Sport / Outdoor', NULL, NULL, 'https://officialmykonos.com/products/mykonos-penthouse-extrait-de-parfum-100ml', 0.0, 0.0, 'Extrait de Parfum', 'Sparkling Blackcurrant, Aldehydes, Mandarin Zest, Rose Mist Middle Notes : Velvety White Floral, White Tea Vapor, White Soap Accord, Cashmere Wood', 'Velvety White Floral, White Tea Vapor, White Soap Accord, Cashmere Wood', 'Tonka Foam, Iso E Super, Amber, Clean Musks, Cashmeran No BPOM : NA18250611825', 'Woody, Floral, Citrus, Oriental', 'Musim Semi', 'Sangat Tahan Lama (8+ jam)', 'Sedang (Moderate)');
