INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('NEW ARRIVALS', 'DIOR', 'Member Exclusive | Receive an additional complimentary Dior Makeup Eyes and Lips Trial Set with min spend of Explore the new Dior fragrance arrivals through the olfactory worlds of Miss Dior, Dior Homme, J�adore and La Collection Priv�e Christian Dior. Eau de parfum, eau de toilette, scented candles, body lotions: discover all the new products. Taming and Hydrating Hair Serum Fragrance - Ambery, Woody and Floral Notes Sauvage Spray For The Wild - Limited Edition 30 ml Bottle and Case - 2 Fragrances Available Sauvage Hydrating Shampoo Nourishing and Softening Men''s Shampoo Privacy Policy Terms and conditions Cookies Policy Cookies are in use on this site These cookies are necessary for the website to function and cannot be switched off in our systems. They are usually only set in response to actions made by you which amount to a request for services, such as setting your privacy preferences, logging in or filling in forms. You can set your browser to block or alert you about these cookies, but some parts of the site will not then work. These cookies enable the website to provide enhanced functionality and personalisation. They may be set by us or by third party providers whose services we have added to our pages. If you do not allow these cookies then some or all of these services may not function properly. These cookies may be set through our site by our advertising partners. They may be used by those companies to build a profile of your interests and show you relevant adverts on other sites. They do not store directly personal information, but are based on uniquely identifying your browser and internet device. If you do not allow these cookies, you will experience less targeted advertising. These cookies are set by a range of social media services that we have added to the site to enable you to share our content with your friends and networks. They are capable of tracking your browser across other sites and building up a profile of your interests. This may impact the content and messages you see on other websites you visit. If you do not allow these cookies you may not be able to use or see these sharing tools. These cookies allow us to count visits and traffic sources so we can measure and improve the performance of our site. They help us to know which pages are the most and least popular and see how visitors move around the site. All information these cookies collect is aggregated and therefore anonymous. If you do not allow these cookies we will not know when you have visited our site, and will not be able to monitor its performance.', NULL, 0.0, 'Wanita', 'Malam', 'Office / Formal', NULL, NULL, 'https://www.dior.com/en_id/beauty/productlist-folder/plp-fragrance-men-new-arrivals.html', 0.0, 0.0, 'Eau de Parfum (EDP)', 'Lime', 'Sage', 'Amber', 'Woody, Floral, Citrus, Oriental', 'Musim Semi', 'Tahan Lama (4-8 jam)', 'Kuat (Moderate-Heavy)');
