INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Rose Star', 'DIOR', 'Unisex Eau de Parfum - Floral and Ambery Notes description ingredients application tips olfactory notes description ROSE STAR, THE SILHOUETTE OF DESTINY Rose Star pays homage to two eternal Christian Dior symbols: his lucky star and his iconic flower, the rose. Its fragrance unfurls into different facets of rose, imagined as the 5 points of the Dior guiding star. The top notes of the fragrance are zesty and fruity, blending with a note of Sichuan pepper. They are followed by honeyed and musky accords, giving way to an intense, unexpected trail. An allegorical fragrance, Rose Star is the olfactory embodiment of the original passions that inspired the world of Christian Dior. The perfumer-creator�s star is now revealed within the notes of this rose of destiny, Rose Star. ingredients #21453 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � DIETHYLAMINO HYDROXYBENZOYL HEXYL BENZOATE � LINALOOL � LIMONENE � ALPHA-ISOMETHYL IONONE � CITRONELLOL � GERANIOL � CI 60730 (EXT. VIOLET 2) � CI 17200 (RED 33) � CI 47005 (YELLOW 10) application tips Spray Rose Star on pulse points � neck and wrists � or on a mitzah scarf. olfactory notes Heart Notes Centifolia rose absolute, damascus rose essence and fruity notes A fruity note oscillating between a lychee, a raspberry and a pear, a sensual, deep and persistent honeyed note and a musky note, as enveloping and soft as a petal. * At Dior. Top Notes Sichuan pepper extract The full-bodied density of the Sichuan pepper note accentuates the spicy facet of the rose. MEMBER OF THE UNION FOR ETHICAL BIOTRADE, THE HOUSE OF DIOR IS COMMITTED TO SOURCING THAT IS RESPECTFUL OF NATURE AND LOCAL COMMUNITIES. description ingredients application ti