INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Sauvage Eau de Parfum', 'DIOR', 'Eau de Parfum - Citrus and Vanilla Notes - Refillable description ingredients application tips olfactory notes description Inspiration for the creation of Sauvage Eau de Parfum was taken from the desert in the magical hour of twilight: mixed with the coolness of the night, the burning desert air exudes profound scents. Sauvage Eau de Parfum is thus the olfactory interpretation of a moment tinted with a thick blue that unleashes the wildest instincts. In the hour when the wolves come out and the sky is set ablaze, a new magic unfolds. Sauvage Eau de Parfum teams the freshness of a juicy, spicy Calabrian bergamot note with the sensuality of a mysterious and enveloping Papua New Guinean vanilla extract accord to unfurl a powerful and noble trail. The 100 ml bottle of Sauvage Eau de Parfum is now refillable with the Sauvage Eau de Parfum refill. It can also be refilled at the Sauvage Refill Station, available at selected sales locations. This innovative system is part of Dior''s sustainable development initiative, which aims to improve the House of Dior''s impact on the climate, resources and waste. ingredients #16095 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � LIMONENE � LINALOOL � BUTYL METHOXYDIBENZOYLMETHANE � TRIETHYL CITRATE � COUMARIN � CITRONELLOL � CITRAL � PENTAERYTHRITYL TETRA-DI-T-BUTYL HYDROXYHYDROCINNAMATE � GERANIOL � CI 14700 (RED 4) � CI 42090 (BLUE 1) � CI 47005 (YELLOW 10) � CI 60730 (EXT. VIOLET 2) application tips 1. Cleanse with Sauvage Shower Gel. 2. Hydrate your skin with Sauvage Moisturizer for Face and Beard. 3. Complete the Sauvage ritual by applying Sauvage Eau de Parfum on pulse points: wrists and neck. olfactory notes Heart Notes Papua New Guinean Vanilla Extract Papua New Guinean vanilla extract unfurls an irresistibly delicious attraction with smoky accents that render it more virile. Harvested green and then scalded, this exceptional vanilla is processed using a solvent-free extraction method to restore the complex power of its aromas while preserving the environment. Top Notes Reggio di Calabria Bergamot This bergamot is a whirlwind of juicy freshness that seems to sweep up everything in its trail. Drenched in the Calabrian sun, it is fruitier than other bergamots and develops slightly peppery and zesty facets. A MEMBER OF THE UNION FOR ETHICAL BIOTRADE, DIOR IS COMMITTED TO A SOURCING THAT IS RESPECTFUL OF NATURE AND COMMUNITIES. These products might interest you IDR C099600670 DIOR Y0996472 950000.0 true MEN�S FRAGRANCE SAUVAGE Bath & Shaving Sauvage Shower Gel C099600670 1.0 regular Sauvage Shower Gel Shower Gel - Cleanses and Refreshes 250 mL IDR F001802000 DIOR Y0018020 700000.0 false MEN�S FRAGRANCE Sauvage Sauvage F001802000 1.0 regular Sauvage Stick deodorant 75 g description ingredients application tips olfactory notes description Inspiration for the creation of Sauvage Eau de Parfum was taken from the desert in the magical hour of twilight: mixed with the coolness of the night, the burning desert air exudes profound scents. Sauvage Eau de Parfum is thus the olfactory interpretation of a moment tinted with a thick blue that unleashes the wildest instincts. In the hour when the wolves come out and the sky is set ablaze, a new magic unfolds. Sauvage Eau de Parfum teams the freshness of a juicy, spicy Calabrian bergamot note with the sensuality of a mysterious and enveloping Papua New Guinean vanilla extract accord to unfurl a powerful and noble trail. The 100 ml bottle of Sauvage Eau de Parfum is now refillable with the Sauvage Eau de Parfum refill. It can also be refilled at the Sauvage Refill Station, available at selected sales locations. This innovative system is part of Dior''s sustainable development initiative, which aims to improve the House of Dior''s impact on the climate, resources and waste. ingredients #16095 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � LIMONENE � LINALOOL � BUTYL METHOXYDIBENZOYLMETHANE � TRIETHYL CITRATE � COUMARIN � CITRONELLOL � CITRAL � PENTAERYTHRITYL TETRA-DI-T-BUTYL HYDROXYHYDROCINNAMATE � GERANIOL � CI 14700 (RED 4) � CI 42090 (BLUE 1) � CI 47005 (YELLOW 10) � CI 60730 (EXT. VIOLET 2) application tips 1. Cleanse with Sauvage Shower Gel. 2. Hydrate your skin with Sauvage Moisturizer for Face and Beard. 3. Complete the Sauvage ritual by applying Sauvage Eau de Parfum on pulse points: wrists and neck. olfactory notes Heart Notes Papua New Guinean Vanilla Extract Papua New Guinean vanilla extract unfurls an irresistibly delicious attraction with smoky accents that render it more virile. Harvested green and then scalded, this exceptional vanilla is processed using a solvent-free extraction method to restore the complex power of its aromas while preserving the environment. Top Notes Reggio di Calabria Bergamot This bergamot is a whirlwind of juicy freshness that seems to sweep up everything in its trail. Drenched in the Calabrian sun, it is fruitier than other bergamots and develops slightly peppery and zesty facets. A MEMBER OF THE UNION FOR ETHICAL BIOTRADE, DIOR IS COMMITTED TO A SOURCING THAT IS RESPECTFUL OF NATURE AND COMMUNITIES. description Inspiration for the creation of Sauvage Eau de Parfum was taken from the desert in the magical hour of twilight: mixed with the coolness of the night, the burning desert air exudes profound scents. Sauvage Eau de Parfum is thus the olfactory interpretation of a moment tinted with a thick blue that unleashes the wildest instincts. In the hour when the wolves come out and the sky is set ablaze, a new magic unfolds. Sauvage Eau de Parfum teams the freshness of a juicy, spicy Calabrian bergamot note with the sensuality of a mysterious and enveloping Papua New 