INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Sauvage Eau de Toilette', 'DIOR', 'Eau de Toilette - Fresh, Citrus and Woody Notes - Refillable description ingredients application tips olfactory notes description Sauvage is an act of creation inspired by wide-open spaces. An ozone blue sky that dominates a white-hot rocky landscape. The strong gust of citrus in Sauvage Eau de Toilette is powerfully anchored by the ambery nobleness of ambroxan, resinous elemi and woods. Instantly recognizable, it has become a genuine signature scent, unique* in its confident virility. Like a deep breath of fresh air, Sauvage Eau de Toilette is a bold composition for a man who is authentic and true. The 30 ml and 100 ml bottles of Sauvage Eau de Toilette are refillable with the Sauvage Eau de Toilette refill. The 100 ml bottle can also be refilled at the Sauvage Refill Station, available at selected sales locations. This innovative system is part of Dior''s sustainable development initiative, which aims to improve the House of Dior''s impact on the climate, resources and waste. * At Dior. ingredients #16097 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � LIMONENE � LINALOOL � TRIETHYL CITRATE � BUTYL METHOXYDIBENZOYLMETHANE � CITRONELLOL � COUMARIN � CITRAL � PENTAERYTHRITYL TETRA-DI-T-BUTYL HYDROXYHYDROCINNAMATE � GERANIOL � CI 60730 (EXT. VIOLET 2) � CI 14700 (RED 4) � CI 42090 (BLUE 1) � CI 47005 (YELLOW 10) application tips 1. Cleanse with Sauvage Shower Gel. 2. Hydrate your skin with Sauvage Moisturizer for Face and Beard. 3. Complete the Sauvage ritual by applying Sauvage Eau de Toilette on pulse points: wrists and neck. olfactory notes Heart Notes Ambroxan It unfurls its marine woody notes, as vivifying as ocean spray. With the subtle attraction of sun-bleached driftwood, it leaves a distinguished trail that never fades. Top Notes Bergamot from Reggio di Calabria For the House of Dior, Fran�ois Demachy chose an exclusive Bergamot that he shaped with local producers to obtain a "custom" signature. His Bergamot is a whirlwind of juicy freshness that seems to sweep up everything in its path. Drenched in the Calabrian sun, it is fruitier and develops unique, slightly peppery and zesty facets. A MEMBER OF THE UNION FOR ETHICAL BIOTRADE, DIOR IS COMMITTED TO A SOURCING THAT IS RESPECTFUL OF NATURE AND COMMUNITIES. These products might interest you IDR C099600670 DIOR Y0996472 950000.0 true MEN�S FRAGRANCE SAUVAGE Bath & Shaving Sauvage Shower Gel C099600670 1.0 regular Sauvage Shower Gel Shower Gel - Cleanses and Refreshes 250 mL IDR F001802000 DIOR Y0018020 700000.0 false MEN�S FRAGRANCE Sauvage Sauvage F001802000 1.0 regular Sauvage Stick deodorant 75 g description ingredients application tips olfactory notes description Sauvage is an act of creation inspired by wide-open spaces. An ozone blue sky that dominates a white-hot rocky landscape. The strong gust of citrus in Sauvage Eau de Toilette is powerfully anchored by the ambery nobleness of ambroxan, resinous elemi and woods. Instantly recognizable, it has become a genuine signature scent, unique* in its confident virility. Like a deep breath of fresh air, Sauvage Eau de Toilette is a bold composition for a man who is authentic and true. The 30 ml and 100 ml bottles of Sauvage Eau de Toilette are refillable with the Sauvage Eau de Toilette refill. The 100 ml bottle can also be refilled at the Sauvage Refill Station, available at selected sales locations. This innovative system is part of Dior''s sustainable development initiative, which aims to improve the House of Dior''s impact on the climate, resources and waste. * At Dior. ingredients #16097 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � LIMONENE � LINALOOL � TRIETHYL CITRATE � BUTYL METHOXYDIBENZOYLMETHANE � CITRONELLOL � COUMARIN � CITRAL � PENTAERYTHRITYL TETRA-DI-T-BUTYL HYDROXYHYDROCINNAMATE � GERANIOL � CI 60730 (EXT. VIOLET 2) � CI 14700 (RED 4) � CI 42090 (BLUE 1) � CI 47005 (YELLOW 10) application tips 1. Cleanse with Sauvage Shower Gel. 2. Hydrate your skin with Sauvage Moisturizer for Face and Beard. 3. Complete the Sauvage ritual by applying Sauvage Eau de Toilette on pulse points: wrists and neck. olfactory notes Heart Notes Ambroxan It unfurls its marine woody notes, as vivifying as ocean spray. With the subtle attraction of sun-bleached driftwood, it leaves a distinguished trail that never fades. Top Notes Bergamot from Reggio di Calabria For the House of Dior, Fran�ois Demachy chose an exclusive Bergamot that he shaped with local producers to obtain a "custom" signature. His Bergamot is a whirlwind of juicy freshness that seems to sweep up everything in its path. Drenched in the Calabrian sun, it is fruitier and develops unique, slightly peppery and zesty facets. A MEMBER OF THE UNION FOR ETHICAL BIOTRADE, DIOR IS COMMITTED TO A SOURCING THAT IS RESPECTFUL OF NATURE AND COMMUNITIES. description Sauvage is an act of creation inspired by wide-open spaces. An ozone blue sky that dominates a white-hot rocky landscape. The strong gust of citrus in Sauvage Eau de Toilette is powerfully anchored by the ambery nobleness of ambroxan, resinous elemi and woods. Instantly recognizable, it has become a genuine signature scent, unique* in its confident virility. Like a deep breath of fresh air, Sauvage Eau de Toilette is a bold composition for a man who is authentic and true. The 30 ml and 100 ml bottles of Sauvage Eau de Toilette are refillable with the Sauvage Eau de Toilette refill. The 100 ml bottle can also be refilled at the Sauvage Refill Station, available at selected sales locations. This innovative system is part of Dior''s sustainable development initiative, which aims to improve the House of Dior''s impact on the climate, resources and waste. * At Dio