INSERT INTO public.perfumes (nama_parfum, brand, description, notes, harga, gender_target, waktu_penggunaan, occasion, wangi_vibe, url_foto, url_produk, rating_value, rating_count, concentration, top_notes, middle_notes, base_notes, main_accords, cuaca_musim, longevity, sillage) VALUES ('Sauvage Elixir', 'DIOR', 'Elixir - Spicy, Fresh and Woody Notes description ingredients application tips olfactory notes description Sauvage Elixir is an extraordinarily* concentrated fragrance steeped in the emblematic freshness of Sauvage with an intoxicating heart of spices, a "tailor-made" lavender essence and a blend of rich woods forming the signature of its powerful, lavish and captivating trail. The Sauvage Elixir fragrance was created like a fine liqueur made of exceptional ingredients. This concentration was made possible by the exceptional quality of the raw materials: Sauvage Elixir is a fragrance as unique and rare as a red moon in the night sky. Sauvage Elixir concentrates all of its power in a midnight blue lacquered glass bottle in a unique* 60 ml size. This precious bottle, shaped like a vial, features multiple sophisticated designs: the magical name of the fragrance is inscribed in shiny silver on a label engraved right into the glass. The dome-shaped bottom engraved with the CD logo marks its silhouette. * At Dior.1 ingredients #15755 ALCOHOL � PARFUM (FRAGRANCE) � AQUA (WATER) � LINALOOL � LIMONENE � COUMARIN � CITRONELLOL � EUGENOL � BUTYL METHOXYDIBENZOYLMETHANE � TRIETHYL CITRATE � PENTAERYTHRITYL TETRA-DI-T-BUTYL HYDROXYHYDROCINNAMATE � GERANIOL � CINNAMAL � CITRAL � EVERNIA FURFURACEA (TREEMOSS) EXTRACT � FARNESOL � ISOEUGENOL � CI 60730 (EXT. VIOLET 2) � CI 19140 (YELLOW 5) � CI 42090 (BLUE 1) application tips 1. Cleanse your skin with Sauvage Shower Gel. 2. Soothe razor burn with Sauvage After-shave Lotion. >3. Apply Sauvage Elixir on pulse points. olfactory notes Base Notes Rich woods An ambery accord, the powerful Sauvage signature, reveals its full range of velvety and sensual nuances. Enveloping, it blankets the base heightened with a sweet, smooth licorice note. Haitian vetiver and a patchouli heart form the link between these rich woods. Heart Notes Essence of AOP lavender from Nyons A blend of several carefully selected harvests, this AOP essence from Nyons reveals unique* facets and releases notes that are as close as possible to the wild flower. Fresh but not camphorous, graced with a vanilla-tinged coumarin note, it is rich, fine and floral. Top Notes Grapefruit note and heart of spices Top notes burst with a lively, persistent grapefruit note and heady spices. Some, like the essences of cinnamon and nutmeg, play with heat and sensuality, while others are more refreshing, like the zesty and aromatic cardamom. A MEMBER OF THE UNION FOR ETHICAL BIOTRADE, DIOR IS COMMITTED TO A SOURCING THAT IS RESPECTFUL OF NATURE AND COMMUNITIES. * At Dior These products might interest you IDR C099600670 DIOR Y0996472 950000.0 true MEN�S FRAGRANCE SAUVAGE Bath & Shaving Sauvage Shower Gel C099600670 1.0 regular Sauvage Shower Gel Shower Gel - Cleanses and Refreshes 250 mL IDR F001802000 DIOR Y0018020 700000.0 false MEN�S FRAGRANCE Sauvage Sauvage F001802000 1.0 regular Sauvage Stick deodorant 75 g description ingredients application tips olfactory notes description Sauvage Elixir is an extraordinarily* concentrated fragrance steeped in the emblematic freshness of Sauvage with an intoxicating heart of spices, a "tailor-made" lavender essence and a blend of rich woods forming the signature of its powerful, lavish and captivating trail. The Sauvage Elixir fragrance was created like a fine liqueur made of exceptional ingredients. This concentration was made possible by the exceptional quality of the raw materials: Sauvage Elixir is a fragrance as unique and rare as a red moon in the night sky. Sauvage Elixir concentrates all of its power in a midnight blue lacquered glass bottle in a unique* 60 ml size. This precious bottle, sha